SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-inductance", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "Two inductors of self-inductances L₁ and L₂ are connected in series with no mutual coupling. The equivalent inductance is:", "explanation": "When inductors are in series with no mutual coupling (M = 0), the equivalent inductance is simply L = L₁ + L₂. This is analogous to resistors in series. If there is mutual coupling, L = L₁ + L₂ ± 2M (+ for aiding, − for opposing).", "correct_answer": "A", "concept_tags": ["inductors-in-series", "equivalent-inductance", "no-coupling"], "payload": {"question_id": "cuet-phy-emi-inductance-19", "subtopic": "combination of inductors", "topic_name": "Self and Mutual Inductance", "bloom_level": "remember", "options": [{"key": "A", "value": "L₁ + L₂", "is_correct": true}, {"key": "B", "value": "L₁L₂/(L₁ + L₂)", "is_correct": false}, {"key": "C", "value": "L₁ − L₂", "is_correct": false}, {"key": "D", "value": "√(L₁L₂)", "is_correct": false}], "elimination_hints": ["Inductors in series add directly, just like resistors in series.", "L₁L₂/(L₁ + L₂) is the formula for inductors in parallel.", "L₁ − L₂ would give negative inductance if L₂ > L₁, which is unphysical for no coupling."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-inductance", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "Two inductors of self-inductances L₁ and L₂ are connected in parallel with no mutual coupling. The equivalent inductance is:", "explanation": "For inductors in parallel (no mutual coupling): 1/L = 1/L₁ + 1/L₂, giving L = L₁L₂/(L₁ + L₂). This is analogous to resistors in parallel.", "correct_answer": "B", "concept_tags": ["inductors-in-parallel", "equivalent-inductance", "no-coupling"], "payload": {"question_id": "cuet-phy-emi-inductance-20", "subtopic": "combination of inductors", "topic_name": "Self and Mutual Inductance", "bloom_level": "remember", "options": [{"key": "A", "value": "L₁ + L₂", "is_correct": false}, {"key": "B", "value": "L₁L₂/(L₁ + L₂)", "is_correct": true}, {"key": "C", "value": "(L₁ + L₂)/L₁L₂", "is_correct": false}, {"key": "D", "value": "L₁ + L₂ + 2M", "is_correct": false}], "elimination_hints": ["Inductors combine like resistors: parallel gives the reciprocal formula.", "L₁ + L₂ is the series combination, not parallel.", "(L₁ + L₂)/L₁L₂ = 1/L, not L itself — you need to take the reciprocal."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-inductance", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "An inductor opposes any change in the current flowing through it. This property is called:", "explanation": "Self-induction is the property by which an inductor opposes any change in current through it. When current increases, the back-EMF opposes the increase; when current decreases, the back-EMF opposes the decrease. This is often called electrical inertia.", "correct_answer": "A", "concept_tags": ["self-induction", "back-emf", "electrical-inertia"], "payload": {"question_id": "cuet-phy-emi-inductance-21", "subtopic": "self-induction concept", "topic_name": "Self and Mutual Inductance", "bloom_level": "understand", "options": [{"key": "A", "value": "Self-induction", "is_correct": true}, {"key": "B", "value": "Mutual induction", "is_correct": false}, {"key": "C", "value": "Electromagnetic induction", "is_correct": false}, {"key": "D", "value": "Eddy current effect", "is_correct": false}], "elimination_hints": ["Mutual induction involves two separate coils, not a single coil opposing its own current change.", "Electromagnetic induction is the general phenomenon; the specific property of opposing current change is self-induction.", "Eddy currents are induced in bulk conductors, not in the coil itself."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-inductance", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The phenomenon of self-induction is sometimes called the ''inertia of electricity'' because:", "explanation": "Just as mechanical inertia opposes changes in velocity, self-induction opposes changes in current. An inductor resists both increase and decrease of current, analogous to how a massive object resists both acceleration and deceleration.", "correct_answer": "D", "concept_tags": ["self-induction", "electrical-inertia", "analogy"], "payload": {"question_id": "cuet-phy-emi-inductance-22", "subtopic": "self-induction concept", "topic_name": "Self and Mutual Inductance", "bloom_level": "understand", "options": [{"key": "A", "value": "It produces current in the coil", "is_correct": false}, {"key": "B", "value": "It increases the current rapidly", "is_correct": false}, {"key": "C", "value": "It stores charge in the coil", "is_correct": false}, {"key": "D", "value": "It opposes any change in the current through the coil", "is_correct": true}], "elimination_hints": ["Self-induction does not produce current — it opposes changes to existing current.", "It actually slows down rapid current changes, not increases them.", "An inductor stores energy in its magnetic field, not charge."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-inductance", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A solenoid of length 0.5 m has 500 turns and area of cross-section 2 × 10⁻⁴ m². If a current of 3 A flows through it, the energy stored in the solenoid is approximately:", "explanation": "L = μ₀N²A/l = 4π × 10⁻⁷ × (500)² × 2 × 10⁻⁴ / 0.5 = 4π × 10⁻⁷ × 25 × 10⁴ × 2 × 10⁻⁴ / 0.5 = 4π × 10⁻⁷ × 100 = 4π × 10⁻⁵ H. Energy U = (1/2)LI² = (1/2) × 4π × 10⁻⁵ × 9 = 18π × 10⁻⁵ ≈ 5.65 × 10⁻⁴ J ≈ 0.56 mJ.", "correct_answer": "B", "concept_tags": ["energy-stored", "solenoid", "numerical-problem"], "payload": {"question_id": "cuet-phy-emi-inductance-23", "subtopic": "energy in inductor", "topic_name": "Self and Mutual Inductance", "bloom_level": "apply", "options": [{"key": "A", "value": "0.056 mJ", "is_correct": false}, {"key": "B", "value": "0.56 mJ", "is_correct": true}, {"key": "C", "value": "5.6 mJ", "is_correct": false}, {"key": "D", "value": "56 mJ", "is_correct": false}], "elimination_hints": ["First find L, then use U = (1/2)LI².", "L = μ₀N²A/l ≈ 4π × 10⁻⁵ H ≈ 1.26 × 10⁻⁴ H.", "U = 0.5 × 1.26 × 10⁻⁴ × 9 ≈ 5.65 × 10⁻⁴ J ≈ 0.56 mJ."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-inductance", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The mutual inductance between two coils depends on:", "explanation": "Mutual inductance depends on: (1) the number of turns in both coils, (2) the area of cross-section, (3) the distance and orientation between the coils, (4) the medium between them (permeability). It does NOT depend on the current in either coil.", "correct_answer": "D", "concept_tags": ["mutual-inductance", "factors", "geometry"], "payload": {"question_id": "cuet-phy-emi-inductance-24", "subtopic": "factors affecting mutual inductance", "topic_name": "Self and Mutual Inductance", "bloom_level": "understand", "options": [{"key": "A", "value": "Current in either coil", "is_correct": false}, {"key": "B", "value": "Resistance of the coils", "is_correct": false}, {"key": "C", "value": "EMF applied to the coils", "is_correct": false}, {"key": "D", "value": "Geometry, number of turns, and the medium between them", "is_correct": true}], "elimination_hints": ["M = μ₀N₁N₂A/l — there is no I or R in this formula.", "Current determines the flux magnitude, but mutual inductance is a geometric property.", "EMF is a consequence of changing current, not a factor in determining M."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-inductance", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "In an LR circuit connected to a battery of EMF ε, the time constant τ is:", "explanation": "The time constant of an LR circuit is τ = L/R. After one time constant, the current reaches (1 − 1/e) ≈ 63.2% of its maximum value ε/R. The time constant determines how quickly current builds up or decays in an inductive circuit.", "correct_answer": "A", "concept_tags": ["LR-circuit", "time-constant", "exponential-growth"], "payload": {"question_id": "cuet-phy-emi-inductance-25", "subtopic": "LR circuit", "topic_name": "Self and Mutual Inductance", "bloom_level": "remember", "options": [{"key": "A", "value": "L/R", "is_correct": true}, {"key": "B", "value": "R/L", "is_correct": false}, {"key": "C", "value": "LR", "is_correct": false}, {"key": "D", "value": "√(LR)", "is_correct": false}], "elimination_hints": ["τ has units of time. L/R = H/Ω = (V·s/A)/(V/A) = s — correct.", "R/L has units of 1/s — the inverse of time.", "LR has units of H·Ω = V·s/A × V/A = V²s/A² — not seconds."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-inductance", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "In an LR circuit, the current during growth is given by I = (ε/R)(1 − e^(−t/τ)). The current at t = τ is approximately:", "explanation": "At t = τ: I = (ε/R)(1 − e⁻¹) = (ε/R)(1 − 1/e) = (ε/R)(1 − 0.368) = 0.632(ε/R). So the current reaches about 63.2% of its maximum value in one time constant.", "correct_answer": "C", "concept_tags": ["LR-circuit", "current-growth", "time-constant"], "payload": {"question_id": "cuet-phy-emi-inductance-26", "subtopic": "LR circuit", "topic_name": "Self and Mutual Inductance", "bloom_level": "apply", "options": [{"key": "A", "value": "ε/R", "is_correct": false}, {"key": "B", "value": "0.5(ε/R)", "is_correct": false}, {"key": "C", "value": "0.632(ε/R)", "is_correct": true}, {"key": "D", "value": "0.368(ε/R)", "is_correct": false}], "elimination_hints": ["ε/R is the maximum current (at t → ∞), not at t = τ.", "0.368(ε/R) = (ε/R)e⁻¹ — this is the remaining fraction after decay, not the growth value.", "1 − e⁻¹ ≈ 1 − 0.368 = 0.632, not 0.5."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-inductance", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "In an LR circuit, during the decay of current, the current is given by I = I₀e^(−Rt/L). After time t = L/R, the current reduces to:", "explanation": "At t = L/R = τ: I = I₀e⁻¹ = I₀/e ≈ 0.368I₀ = 36.8% of I₀. The current decays to about 37% of its initial value in one time constant.", "correct_answer": "B", "concept_tags": ["LR-circuit", "current-decay", "time-constant"], "payload": {"question_id": "cuet-phy-emi-inductance-27", "subtopic": "LR circuit", "topic_name": "Self and Mutual Inductance", "bloom_level": "apply", "options": [{"key": "A", "value": "I₀/2", "is_correct": false}, {"key": "B", "value": "I₀/e", "is_correct": true}, {"key": "C", "value": "I₀/e²", "is_correct": false}, {"key": "D", "value": "Zero", "is_correct": false}], "elimination_hints": ["I₀/2 corresponds to the half-life, which is t₁/₂ = τ ln2 ≈ 0.693τ, not τ.", "At t = τ, I = I₀e⁻¹ = I₀/e ≈ 0.368I₀.", "I₀/e² corresponds to t = 2τ, not one time constant."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-inductance", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "Eddy currents are produced in:", "explanation": "Eddy currents are circulating currents induced in bulk conducting materials (not just wires) when they experience changing magnetic flux. They are called ''eddy'' because they flow in closed loops within the conductor, like eddies in water.", "correct_answer": "C", "concept_tags": ["eddy-currents", "bulk-conductors", "induced-currents"], "payload": {"question_id": "cuet-phy-emi-inductance-28", "subtopic": "eddy currents", "topic_name": "Self and Mutual Inductance", "bloom_level": "remember", "options": [{"key": "A", "value": "Insulating materials", "is_correct": false}, {"key": "B", "value": "Semiconductors only", "is_correct": false}, {"key": "C", "value": "Bulk conducting materials", "is_correct": true}, {"key": "D", "value": "Vacuum", "is_correct": false}], "elimination_hints": ["Insulators do not have free electrons to sustain eddy currents.", "While semiconductors can have some eddy currents, the primary and dominant effect is in conductors.", "Eddy currents require free charge carriers moving in closed loops — only conductors provide this."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-inductance", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "Eddy currents can be minimized by:", "explanation": "Eddy currents are minimized by laminating the core — using thin sheets of metal insulated from each other. This breaks the conducting path and limits the area of eddy current loops, reducing their magnitude. This is why transformer cores are laminated.", "correct_answer": "B", "concept_tags": ["eddy-currents", "lamination", "minimization"], "payload": {"question_id": "cuet-phy-emi-inductance-29", "subtopic": "eddy currents", "topic_name": "Self and Mutual Inductance", "bloom_level": "understand", "options": [{"key": "A", "value": "Using a solid metal core", "is_correct": false}, {"key": "B", "value": "Using a laminated core", "is_correct": true}, {"key": "C", "value": "Increasing the thickness of the core", "is_correct": false}, {"key": "D", "value": "Using a core of higher conductivity", "is_correct": false}], "elimination_hints": ["A solid core provides large continuous conducting paths — maximizing eddy currents.", "Increasing thickness increases the area for eddy current loops.", "Higher conductivity means lower resistance, which increases eddy currents."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-inductance", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "Which of the following is NOT an application of eddy currents?", "explanation": "Eddy currents are used in electromagnetic braking, induction furnaces, speedometers (eddy current drag), and metal detectors. Charging a battery requires DC current from a chemical or electrical source, not eddy currents.", "correct_answer": "D", "concept_tags": ["eddy-currents", "applications", "conceptual"], "payload": {"question_id": "cuet-phy-emi-inductance-30", "subtopic": "eddy currents", "topic_name": "Self and Mutual Inductance", "bloom_level": "understand", "options": [{"key": "A", "value": "Electromagnetic braking", "is_correct": false}, {"key": "B", "value": "Induction furnace", "is_correct": false}, {"key": "C", "value": "Electric speedometer", "is_correct": false}, {"key": "D", "value": "Charging a battery", "is_correct": true}], "elimination_hints": ["Electromagnetic brakes use eddy currents to provide a retarding force.", "Induction furnaces use eddy current heating to melt metals.", "Battery charging requires a sustained DC source — eddy currents are dissipative and cannot charge batteries."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-inductance", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "Eddy currents produce a heating effect because:", "explanation": "Eddy currents flow through the resistance of the conducting material. By Joule''s law (P = I²R), the current produces heat. This is the principle used in induction furnaces and induction cooktops.", "correct_answer": "A", "concept_tags": ["eddy-currents", "heating-effect", "joule-heating"], "payload": {"question_id": "cuet-phy-emi-inductance-31", "subtopic": "eddy currents", "topic_name": "Self and Mutual Inductance", "bloom_level": "understand", "options": [{"key": "A", "value": "They flow through a resistance producing I²R losses", "is_correct": true}, {"key": "B", "value": "They increase the magnetic field", "is_correct": false}, {"key": "C", "value": "They store energy in the magnetic field", "is_correct": false}, {"key": "D", "value": "They reduce the resistance of the conductor", "is_correct": false}], "elimination_hints": ["Eddy currents actually oppose the magnetic field change (Lenz''s law), they don''t increase it.", "Energy stored in the magnetic field is a property of inductors, not eddy currents.", "All current through a resistance dissipates energy as heat — this is Joule heating."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-inductance", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "The mutual inductance between a straight long wire and a square loop of side a at a distance d from the wire is proportional to:", "explanation": "The magnetic field due to a long wire varies as B = μ₀I/(2πr). The flux through the square loop requires integration: Φ = ∫ₐ^(d+a) [μ₀I/(2πr)] × a dr = (μ₀Ia/2π) ln[(d+a)/d]. So M = Φ/I = (μ₀a/2π) ln[(d+a)/d], which involves ln and is not simply proportional to a power of d.", "correct_answer": "C", "concept_tags": ["mutual-inductance", "wire-and-loop", "logarithmic-dependence"], "payload": {"question_id": "cuet-phy-emi-inductance-32", "subtopic": "mutual inductance calculation", "topic_name": "Self and Mutual Inductance", "bloom_level": "analyze", "options": [{"key": "A", "value": "1/d", "is_correct": false}, {"key": "B", "value": "1/d²", "is_correct": false}, {"key": "C", "value": "ln[(d+a)/d]", "is_correct": true}, {"key": "D", "value": "d²", "is_correct": false}], "elimination_hints": ["The field of a wire varies as 1/r, so integrating over the loop area gives a logarithm.", "1/d dependence would occur only for a point or very small loop (a << d).", "The logarithmic dependence arises from integrating 1/r over the finite width of the loop."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-inductance", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "In electromagnetic braking, the braking force is provided by:", "explanation": "In electromagnetic braking, when a conducting plate moves through a magnetic field, eddy currents are induced in the plate. By Lenz''s law, these eddy currents create a force that opposes the motion of the plate, providing the braking effect. No friction surfaces are needed.", "correct_answer": "B", "concept_tags": ["eddy-currents", "electromagnetic-braking", "lenz-law"], "payload": {"question_id": "cuet-phy-emi-inductance-33", "subtopic": "eddy currents", "topic_name": "Self and Mutual Inductance", "bloom_level": "understand", "options": [{"key": "A", "value": "Frictional force between surfaces", "is_correct": false}, {"key": "B", "value": "Force on eddy currents due to the magnetic field", "is_correct": true}, {"key": "C", "value": "Gravitational pull on the conductor", "is_correct": false}, {"key": "D", "value": "Elastic force of the spring mechanism", "is_correct": false}], "elimination_hints": ["The whole point of electromagnetic braking is that it''s frictionless — no wear and tear.", "Eddy currents in a magnetic field experience a Lorentz force that opposes motion.", "Gravity pulls downward regardless — it cannot provide braking."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-inductance", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "Two coils are connected in series aiding (fluxes add). If L₁ = 2 H, L₂ = 3 H, and M = 1 H, the equivalent inductance is:", "explanation": "For series aiding connection (fluxes in same direction): L_eq = L₁ + L₂ + 2M = 2 + 3 + 2(1) = 7 H. The mutual inductance adds 2M because the flux from each coil links with the other in the same direction.", "correct_answer": "D", "concept_tags": ["series-inductors", "mutual-inductance", "aiding-connection"], "payload": {"question_id": "cuet-phy-emi-inductance-34", "subtopic": "combination of inductors", "topic_name": "Self and Mutual Inductance", "bloom_level": "apply", "options": [{"key": "A", "value": "4 H", "is_correct": false}, {"key": "B", "value": "5 H", "is_correct": false}, {"key": "C", "value": "6 H", "is_correct": false}, {"key": "D", "value": "7 H", "is_correct": true}], "elimination_hints": ["5 H = L₁ + L₂ ignores the mutual inductance contribution.", "6 H = L₁ + L₂ + M uses M instead of 2M.", "For series aiding: L_eq = L₁ + L₂ + 2M (the factor 2 accounts for mutual coupling in both directions)."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-inductance", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "Two coils are connected in series opposing (fluxes subtract). If L₁ = 2 H, L₂ = 3 H, and M = 1 H, the equivalent inductance is:", "explanation": "For series opposing connection (fluxes in opposite directions): L_eq = L₁ + L₂ − 2M = 2 + 3 − 2(1) = 3 H.", "correct_answer": "B", "concept_tags": ["series-inductors", "mutual-inductance", "opposing-connection"], "payload": {"question_id": "cuet-phy-emi-inductance-35", "subtopic": "combination of inductors", "topic_name": "Self and Mutual Inductance", "bloom_level": "apply", "options": [{"key": "A", "value": "1 H", "is_correct": false}, {"key": "B", "value": "3 H", "is_correct": true}, {"key": "C", "value": "5 H", "is_correct": false}, {"key": "D", "value": "7 H", "is_correct": false}], "elimination_hints": ["7 H is the series aiding result (L₁ + L₂ + 2M).", "5 H ignores mutual inductance entirely.", "For series opposing: L_eq = L₁ + L₂ − 2M = 5 − 2 = 3 H."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-inductance", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The dimensional formula of self-inductance is:", "explanation": "L = ε/(dI/dt). The dimensions of EMF (ε) are [ML²T⁻³A⁻¹] and dI/dt has dimensions [AT⁻¹]. So [L] = [ML²T⁻³A⁻¹]/[AT⁻¹] = [ML²T⁻²A⁻²].", "correct_answer": "C", "concept_tags": ["self-inductance", "dimensional-formula", "units"], "payload": {"question_id": "cuet-phy-emi-inductance-36", "subtopic": "dimensions of inductance", "topic_name": "Self and Mutual Inductance", "bloom_level": "apply", "options": [{"key": "A", "value": "[ML²T⁻³A⁻²]", "is_correct": false}, {"key": "B", "value": "[ML²T⁻¹A⁻²]", "is_correct": false}, {"key": "C", "value": "[ML²T⁻²A⁻²]", "is_correct": true}, {"key": "D", "value": "[MLT⁻²A⁻²]", "is_correct": false}], "elimination_hints": ["1 H = 1 V·s/A = 1 kg·m²·s⁻²·A⁻², giving [ML²T⁻²A⁻²].", "Check: V = kg·m²·s⁻³·A⁻¹, so V·s/A = kg·m²·s⁻²·A⁻².", "[MLT⁻²A⁻²] is missing one power of L (length)."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-inductance", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The principle of mutual induction is used in:", "explanation": "A transformer works on the principle of mutual induction. When AC flows through the primary coil, the changing magnetic flux links with the secondary coil, inducing an EMF in it. The ratio of EMFs equals the ratio of turns.", "correct_answer": "A", "concept_tags": ["mutual-induction", "transformer", "application"], "payload": {"question_id": "cuet-phy-emi-inductance-37", "subtopic": "applications of mutual induction", "topic_name": "Self and Mutual Inductance", "bloom_level": "remember", "options": [{"key": "A", "value": "Transformer", "is_correct": true}, {"key": "B", "value": "DC motor", "is_correct": false}, {"key": "C", "value": "Galvanometer", "is_correct": false}, {"key": "D", "value": "Potentiometer", "is_correct": false}], "elimination_hints": ["A DC motor uses the force on a current-carrying conductor in a magnetic field.", "A galvanometer measures current using torque on a current loop.", "A transformer requires two magnetically coupled coils — the essence of mutual induction."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-inductance", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "If the current through an inductor of 2 H changes from 5 A to 1 A in 0.05 s, the average EMF induced is:", "explanation": "|ε| = L|ΔI/Δt| = 2 × |1 − 5|/0.05 = 2 × 4/0.05 = 2 × 80 = 160 V.", "correct_answer": "D", "concept_tags": ["self-inductance", "average-emf", "numerical-problem"], "payload": {"question_id": "cuet-phy-emi-inductance-38", "subtopic": "self-induced EMF", "topic_name": "Self and Mutual Inductance", "bloom_level": "apply", "options": [{"key": "A", "value": "16 V", "is_correct": false}, {"key": "B", "value": "40 V", "is_correct": false}, {"key": "C", "value": "80 V", "is_correct": false}, {"key": "D", "value": "160 V", "is_correct": true}], "elimination_hints": ["ΔI = |1 − 5| = 4 A, Δt = 0.05 s, so ΔI/Δt = 80 A/s.", "EMF = L × ΔI/Δt = 2 × 80 = 160 V.", "80 V would be the answer if L = 1 H."]}}]'::jsonb, 'deploy-2026-03-05-b06');

SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-inductance", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The current in an inductor of self-inductance L is given by I = I₀ sin(ωt). The maximum value of the self-induced EMF is:", "explanation": "ε = −L(dI/dt) = −LI₀ω cos(ωt). The maximum value of |ε| = LI₀ω. This occurs when the current is passing through zero (rate of change is maximum).", "correct_answer": "B", "concept_tags": ["self-inductance", "sinusoidal-current", "peak-emf"], "payload": {"question_id": "cuet-phy-emi-inductance-39", "subtopic": "self-induced EMF", "topic_name": "Self and Mutual Inductance", "bloom_level": "apply", "options": [{"key": "A", "value": "LI₀", "is_correct": false}, {"key": "B", "value": "LI₀ω", "is_correct": true}, {"key": "C", "value": "LI₀/ω", "is_correct": false}, {"key": "D", "value": "LI₀ω²", "is_correct": false}], "elimination_hints": ["Differentiating I₀ sin(ωt) gives I₀ω cos(ωt), so the factor ω appears.", "LI₀ has units of H·A = Wb, not volts.", "LI₀ω has units of H·A·s⁻¹ = V — correct for EMF."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-inductance", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A 100 mH inductor carries a current that increases uniformly from 0 to 10 A in 0.5 s. The power input to the inductor at the instant when the current is 5 A is:", "explanation": "dI/dt = (10 − 0)/0.5 = 20 A/s (uniform rate). EMF = L(dI/dt) = 0.1 × 20 = 2 V. Power input at I = 5 A: P = ε × I = 2 × 5 = 10 W. Alternatively, P = LI(dI/dt) = 0.1 × 5 × 20 = 10 W.", "correct_answer": "C", "concept_tags": ["inductor-power", "energy-storage", "numerical-problem"], "payload": {"question_id": "cuet-phy-emi-inductance-40", "subtopic": "energy in inductor", "topic_name": "Self and Mutual Inductance", "bloom_level": "apply", "options": [{"key": "A", "value": "1 W", "is_correct": false}, {"key": "B", "value": "5 W", "is_correct": false}, {"key": "C", "value": "10 W", "is_correct": true}, {"key": "D", "value": "20 W", "is_correct": false}], "elimination_hints": ["dI/dt = 20 A/s (constant). EMF = L × dI/dt = 0.1 × 20 = 2 V.", "Power = EMF × I = 2 × 5 = 10 W (at the instant when I = 5 A).", "5 W results from using I = 2.5 A or EMF = 1 V."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-em-ac-circuits", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The voltage supplied by an AC source is given by V = V₀ sin(ωt). The peak value and the angular frequency of the source are:", "explanation": "Comparing with V = V₀ sin(ωt): V₀ is the peak (maximum) voltage and ω is the angular frequency in rad/s. The frequency f = ω/(2π) and time period T = 2π/ω.", "correct_answer": "A", "concept_tags": ["ac-voltage", "peak-value", "angular-frequency"], "payload": {"question_id": "cuet-phy-ac-circuits-01", "subtopic": "AC voltage representation", "topic_name": "AC Circuits", "bloom_level": "remember", "options": [{"key": "A", "value": "V₀ and ω", "is_correct": true}, {"key": "B", "value": "V₀/√2 and ω", "is_correct": false}, {"key": "C", "value": "V₀ and ω/(2π)", "is_correct": false}, {"key": "D", "value": "V₀√2 and 2πω", "is_correct": false}], "elimination_hints": ["V₀/√2 is the RMS value, not the peak value.", "ω/(2π) is the frequency f, not the angular frequency.", "The peak value is the coefficient of sin — directly V₀."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-em-ac-circuits", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The RMS value of an alternating current I = I₀ sin(ωt) is:", "explanation": "The RMS (root mean square) value of a sinusoidal AC is I_rms = I₀/√2 ≈ 0.707 I₀. RMS values are used because they give the same heating effect as an equivalent DC current. AC ammeters and voltmeters read RMS values.", "correct_answer": "B", "concept_tags": ["rms-value", "alternating-current", "heating-effect"], "payload": {"question_id": "cuet-phy-ac-circuits-02", "subtopic": "RMS values", "topic_name": "AC Circuits", "bloom_level": "remember", "options": [{"key": "A", "value": "I₀", "is_correct": false}, {"key": "B", "value": "I₀/√2", "is_correct": true}, {"key": "C", "value": "I₀/2", "is_correct": false}, {"key": "D", "value": "2I₀/π", "is_correct": false}], "elimination_hints": ["I₀ is the peak value, not the RMS value.", "I₀/2 is neither the RMS nor the average value.", "2I₀/π is the average (mean) value, not the RMS value."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-em-ac-circuits", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The average value of AC current over one complete cycle is:", "explanation": "For a sinusoidal AC, the average value over one complete cycle is zero because the positive and negative half-cycles are symmetric and cancel out. The average of sin(ωt) over a full period is zero.", "correct_answer": "A", "concept_tags": ["average-value", "full-cycle", "sinusoidal"], "payload": {"question_id": "cuet-phy-ac-circuits-03", "subtopic": "average values", "topic_name": "AC Circuits", "bloom_level": "remember", "options": [{"key": "A", "value": "Zero", "is_correct": true}, {"key": "B", "value": "I₀/√2", "is_correct": false}, {"key": "C", "value": "2I₀/π", "is_correct": false}, {"key": "D", "value": "I₀/2", "is_correct": false}], "elimination_hints": ["I₀/√2 is the RMS value, not the average over a full cycle.", "2I₀/π is the average over a half cycle (positive half only).", "The positive and negative halves of the sine wave are mirror images — they cancel exactly."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-em-ac-circuits", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The average value of AC current over a positive half cycle is:", "explanation": "The average value over the positive half cycle is I_avg = (2/π)I₀ ≈ 0.637 I₀. This is obtained by integrating sin(ωt) from 0 to π and dividing by π: (1/π)∫₀^π I₀ sin(θ)dθ = (1/π)I₀[-cos(θ)]₀^π = 2I₀/π.", "correct_answer": "C", "concept_tags": ["average-value", "half-cycle", "integration"], "payload": {"question_id": "cuet-phy-ac-circuits-04", "subtopic": "average values", "topic_name": "AC Circuits", "bloom_level": "apply", "options": [{"key": "A", "value": "I₀/√2", "is_correct": false}, {"key": "B", "value": "I₀/π", "is_correct": false}, {"key": "C", "value": "2I₀/π", "is_correct": true}, {"key": "D", "value": "πI₀/2", "is_correct": false}], "elimination_hints": ["I₀/√2 is the RMS value, not the average value.", "I₀/π is half the correct answer — the integral gives 2I₀/π.", "πI₀/2 > I₀, which is impossible since the average cannot exceed the peak."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-em-ac-circuits", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "An AC voltage of peak value 200 V is connected across a resistance of 100 Ω. The RMS current in the circuit is:", "explanation": "V_rms = V₀/√2 = 200/√2 = 100√2 V. I_rms = V_rms/R = 100√2/100 = √2 A ≈ 1.414 A.", "correct_answer": "B", "concept_tags": ["rms-current", "pure-resistance", "numerical-problem"], "payload": {"question_id": "cuet-phy-ac-circuits-05", "subtopic": "purely resistive circuit", "topic_name": "AC Circuits", "bloom_level": "apply", "options": [{"key": "A", "value": "1 A", "is_correct": false}, {"key": "B", "value": "√2 A", "is_correct": true}, {"key": "C", "value": "2 A", "is_correct": false}, {"key": "D", "value": "2√2 A", "is_correct": false}], "elimination_hints": ["2 A = V₀/R = 200/100 — this is the peak current, not RMS.", "V_rms = 200/√2, so I_rms = (200/√2)/100 = √2 A.", "1 A would require V_rms = 100 V, but V_rms = 200/√2 ≈ 141 V."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-em-ac-circuits", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "In a purely resistive AC circuit, the phase difference between voltage and current is:", "explanation": "In a purely resistive circuit, voltage and current are in phase — they reach their maximum, minimum, and zero values simultaneously. The phase difference φ = 0°. V = V₀ sin(ωt) and I = I₀ sin(ωt), both with the same phase.", "correct_answer": "A", "concept_tags": ["pure-resistance", "phase-difference", "in-phase"], "payload": {"question_id": "cuet-phy-ac-circuits-06", "subtopic": "purely resistive circuit", "topic_name": "AC Circuits", "bloom_level": "remember", "options": [{"key": "A", "value": "0°", "is_correct": true}, {"key": "B", "value": "90°", "is_correct": false}, {"key": "C", "value": "45°", "is_correct": false}, {"key": "D", "value": "180°", "is_correct": false}], "elimination_hints": ["In a resistor, V = IR at every instant — both depend on I the same way.", "90° phase difference occurs in purely inductive or purely capacitive circuits.", "180° would mean V and I are always opposite, which contradicts V = IR (both positive or both negative)."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-em-ac-circuits", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "In a purely inductive AC circuit, the current:", "explanation": "In a purely inductive circuit, the current lags behind the voltage by 90° (π/2 radians). This is because the inductor opposes changes in current. If V = V₀ sin(ωt), then I = I₀ sin(ωt − π/2) = −I₀ cos(ωt). The mnemonic ''ELI'' helps: EMF (E) leads current (I) in an inductor (L).", "correct_answer": "B", "concept_tags": ["pure-inductance", "phase-lag", "current-lags-voltage"], "payload": {"question_id": "cuet-phy-ac-circuits-07", "subtopic": "purely inductive circuit", "topic_name": "AC Circuits", "bloom_level": "remember", "options": [{"key": "A", "value": "Leads the voltage by 90°", "is_correct": false}, {"key": "B", "value": "Lags behind the voltage by 90°", "is_correct": true}, {"key": "C", "value": "Is in phase with the voltage", "is_correct": false}, {"key": "D", "value": "Leads the voltage by 45°", "is_correct": false}], "elimination_hints": ["Remember ''ELI the ICE man'': in L, E leads I (current lags).", "In phase would occur only in a purely resistive circuit.", "45° phase difference does not occur in a purely reactive circuit."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-em-ac-circuits", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The inductive reactance of a coil of inductance L at angular frequency ω is:", "explanation": "Inductive reactance X_L = ωL = 2πfL. It has units of ohms and represents the opposition offered by an inductor to AC. X_L increases with frequency — inductors oppose high-frequency currents more.", "correct_answer": "C", "concept_tags": ["inductive-reactance", "formula", "frequency-dependence"], "payload": {"question_id": "cuet-phy-ac-circuits-08", "subtopic": "purely inductive circuit", "topic_name": "AC Circuits", "bloom_level": "remember", "options": [{"key": "A", "value": "L/ω", "is_correct": false}, {"key": "B", "value": "ω/L", "is_correct": false}, {"key": "C", "value": "ωL", "is_correct": true}, {"key": "D", "value": "1/(ωL)", "is_correct": false}], "elimination_hints": ["L/ω has units of H·s = Ω·s², which is not ohms.", "1/(ωL) is the capacitive reactance formula pattern, not inductive.", "X_L = ωL has units of (rad/s)(H) = (rad/s)(Ω·s) = Ω — correct."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-em-ac-circuits", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "An inductor of 1/π H is connected to a 50 Hz AC source. The inductive reactance is:", "explanation": "X_L = ωL = 2πfL = 2π × 50 × (1/π) = 100 Ω.", "correct_answer": "C", "concept_tags": ["inductive-reactance", "numerical-problem", "frequency"], "payload": {"question_id": "cuet-phy-ac-circuits-09", "subtopic": "purely inductive circuit", "topic_name": "AC Circuits", "bloom_level": "apply", "options": [{"key": "A", "value": "50 Ω", "is_correct": false}, {"key": "B", "value": "50π Ω", "is_correct": false}, {"key": "C", "value": "100 Ω", "is_correct": true}, {"key": "D", "value": "200 Ω", "is_correct": false}], "elimination_hints": ["X_L = 2πfL = 2π × 50 × (1/π) = 2 × 50 = 100 Ω.", "50 Ω uses ω = πf instead of 2πf.", "The π in L = 1/π cancels with the π in ω = 2πf."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-em-ac-circuits", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "In a purely capacitive AC circuit, the current:", "explanation": "In a purely capacitive circuit, current leads the voltage by 90° (π/2). The capacitor starts charging as soon as voltage is applied, so current flows first. If V = V₀ sin(ωt), then I = I₀ sin(ωt + π/2) = I₀ cos(ωt). Mnemonic: ''ICE'' — current (I) leads EMF (E) in a capacitor (C).", "correct_answer": "A", "concept_tags": ["pure-capacitance", "phase-lead", "current-leads-voltage"], "payload": {"question_id": "cuet-phy-ac-circuits-10", "subtopic": "purely capacitive circuit", "topic_name": "AC Circuits", "bloom_level": "remember", "options": [{"key": "A", "value": "Leads the voltage by 90°", "is_correct": true}, {"key": "B", "value": "Lags behind the voltage by 90°", "is_correct": false}, {"key": "C", "value": "Is in phase with the voltage", "is_correct": false}, {"key": "D", "value": "Lags behind the voltage by 45°", "is_correct": false}], "elimination_hints": ["Remember ''ICE'': in C, I leads E — current leads voltage.", "Lagging by 90° happens in a purely inductive circuit (ELI).", "In phase occurs only in a purely resistive circuit."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-em-ac-circuits", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The capacitive reactance of a capacitor of capacitance C at angular frequency ω is:", "explanation": "Capacitive reactance X_C = 1/(ωC) = 1/(2πfC). It has units of ohms and represents the opposition offered by a capacitor to AC. X_C decreases with frequency — capacitors allow high-frequency currents more easily.", "correct_answer": "D", "concept_tags": ["capacitive-reactance", "formula", "frequency-dependence"], "payload": {"question_id": "cuet-phy-ac-circuits-11", "subtopic": "purely capacitive circuit", "topic_name": "AC Circuits", "bloom_level": "remember", "options": [{"key": "A", "value": "ωC", "is_correct": false}, {"key": "B", "value": "ω/C", "is_correct": false}, {"key": "C", "value": "C/ω", "is_correct": false}, {"key": "D", "value": "1/(ωC)", "is_correct": true}], "elimination_hints": ["ωC has units of (rad/s)(F) = (rad/s)(s/Ω) = 1/Ω — inverse of ohms, not ohms.", "1/(ωC) has units of 1/[(rad/s)(F)] = Ω — correct for reactance.", "X_C decreases with ω, so it must have ω in the denominator."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-em-ac-circuits", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A capacitor of 10 μF is connected to a 50 Hz AC source. The capacitive reactance is approximately:", "explanation": "X_C = 1/(2πfC) = 1/(2π × 50 × 10 × 10⁻⁶) = 1/(π × 10⁻³) = 1000/π ≈ 318 Ω.", "correct_answer": "B", "concept_tags": ["capacitive-reactance", "numerical-problem", "frequency"], "payload": {"question_id": "cuet-phy-ac-circuits-12", "subtopic": "purely capacitive circuit", "topic_name": "AC Circuits", "bloom_level": "apply", "options": [{"key": "A", "value": "100 Ω", "is_correct": false}, {"key": "B", "value": "318 Ω", "is_correct": true}, {"key": "C", "value": "500 Ω", "is_correct": false}, {"key": "D", "value": "1000 Ω", "is_correct": false}], "elimination_hints": ["X_C = 1/(2π × 50 × 10⁻⁵) = 1/(π × 10⁻³) = 1000/π ≈ 318 Ω.", "1000 Ω would require forgetting the factor of π.", "100 Ω would result from using f = 50/(2π) instead of 50 Hz."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-em-ac-circuits", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The inductive reactance of a coil is 200 Ω at 50 Hz. Its inductive reactance at 100 Hz will be:", "explanation": "X_L = ωL = 2πfL. Since X_L is directly proportional to frequency, doubling the frequency doubles the reactance. X_L at 100 Hz = 200 × (100/50) = 400 Ω.", "correct_answer": "C", "concept_tags": ["inductive-reactance", "frequency-dependence", "proportionality"], "payload": {"question_id": "cuet-phy-ac-circuits-13", "subtopic": "purely inductive circuit", "topic_name": "AC Circuits", "bloom_level": "apply", "options": [{"key": "A", "value": "100 Ω", "is_correct": false}, {"key": "B", "value": "200 Ω", "is_correct": false}, {"key": "C", "value": "400 Ω", "is_correct": true}, {"key": "D", "value": "800 Ω", "is_correct": false}], "elimination_hints": ["X_L ∝ f. Doubling f doubles X_L.", "100 Ω would result from an inverse relationship (which applies to X_C, not X_L).", "X_L does not remain 200 Ω because it is frequency-dependent."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-em-ac-circuits", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The capacitive reactance of a capacitor is 400 Ω at 50 Hz. Its capacitive reactance at 200 Hz will be:", "explanation": "X_C = 1/(2πfC). X_C is inversely proportional to frequency. When frequency increases by a factor of 4 (50 to 200 Hz), X_C decreases by a factor of 4. X_C = 400/4 = 100 Ω.", "correct_answer": "A", "concept_tags": ["capacitive-reactance", "frequency-dependence", "inverse-proportionality"], "payload": {"question_id": "cuet-phy-ac-circuits-14", "subtopic": "purely capacitive circuit", "topic_name": "AC Circuits", "bloom_level": "apply", "options": [{"key": "A", "value": "100 Ω", "is_correct": true}, {"key": "B", "value": "200 Ω", "is_correct": false}, {"key": "C", "value": "400 Ω", "is_correct": false}, {"key": "D", "value": "1600 Ω", "is_correct": false}], "elimination_hints": ["X_C ∝ 1/f. Frequency increased by 4×, so X_C decreases by 4×.", "1600 Ω would result from a direct proportionality (X_C × 4), which applies to X_L, not X_C.", "X_C cannot remain 400 Ω because it depends on frequency."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-em-ac-circuits", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "In an AC circuit, a capacitor behaves as an open circuit for:", "explanation": "For DC (f = 0), X_C = 1/(2πfC) → ∞. An infinite reactance means no current flows — the capacitor acts as an open circuit. For very high frequencies, X_C → 0, and the capacitor acts as a short circuit.", "correct_answer": "A", "concept_tags": ["capacitive-reactance", "DC-behavior", "frequency-limit"], "payload": {"question_id": "cuet-phy-ac-circuits-15", "subtopic": "purely capacitive circuit", "topic_name": "AC Circuits", "bloom_level": "understand", "options": [{"key": "A", "value": "DC (zero frequency)", "is_correct": true}, {"key": "B", "value": "Very high frequency AC", "is_correct": false}, {"key": "C", "value": "50 Hz AC", "is_correct": false}, {"key": "D", "value": "All frequencies", "is_correct": false}], "elimination_hints": ["At high frequency, X_C → 0, so the capacitor acts as a short circuit, not open.", "A capacitor blocks DC because it cannot sustain a steady current — charges pile up and stop.", "At 50 Hz, the capacitor has a finite reactance and allows some current."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-em-ac-circuits", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "An inductor behaves as a short circuit for:", "explanation": "For DC (f = 0), X_L = ωL = 0. Zero reactance means the inductor offers no opposition — it acts as a short circuit (just a wire with some resistance). For very high frequencies, X_L → ∞, and the inductor acts as an open circuit.", "correct_answer": "B", "concept_tags": ["inductive-reactance", "DC-behavior", "frequency-limit"], "payload": {"question_id": "cuet-phy-ac-circuits-16", "subtopic": "purely inductive circuit", "topic_name": "AC Circuits", "bloom_level": "understand", "options": [{"key": "A", "value": "Very high frequency AC", "is_correct": false}, {"key": "B", "value": "DC (zero frequency)", "is_correct": true}, {"key": "C", "value": "Resonant frequency", "is_correct": false}, {"key": "D", "value": "All frequencies", "is_correct": false}], "elimination_hints": ["At high frequency, X_L = ωL is very large — the inductor acts as an open circuit.", "At f = 0 (DC), ω = 0, so X_L = 0 — the inductor acts as a plain wire.", "At resonant frequency, X_L = X_C, but X_L is not zero."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-em-ac-circuits", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The impedance of a series LCR circuit is given by:", "explanation": "In a series LCR circuit, the impedance Z = √[R² + (X_L − X_C)²] = √[R² + (ωL − 1/(ωC))²]. The net reactance is (X_L − X_C) because V_L and V_C are 180° out of phase and partially cancel.", "correct_answer": "D", "concept_tags": ["impedance", "LCR-circuit", "formula"], "payload": {"question_id": "cuet-phy-ac-circuits-17", "subtopic": "series LCR circuit", "topic_name": "AC Circuits", "bloom_level": "remember", "options": [{"key": "A", "value": "R + X_L + X_C", "is_correct": false}, {"key": "B", "value": "√(R² + X_L² + X_C²)", "is_correct": false}, {"key": "C", "value": "R + (X_L − X_C)", "is_correct": false}, {"key": "D", "value": "√[R² + (X_L − X_C)²]", "is_correct": true}], "elimination_hints": ["V_R, V_L, and V_C are not in phase, so impedances don''t add linearly.", "V_L and V_C are 180° apart, so their net effect is |X_L − X_C|, not √(X_L² + X_C²).", "V_R is 90° out of phase with the net reactive voltage, requiring Pythagorean addition."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-em-ac-circuits", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "In a series LCR circuit at resonance, the impedance is:", "explanation": "At resonance, X_L = X_C, so the net reactance is zero. Z = √[R² + (X_L − X_C)²] = √[R² + 0] = R. The impedance is minimum and equals the resistance. Current is maximum at resonance.", "correct_answer": "B", "concept_tags": ["resonance", "impedance", "minimum-impedance"], "payload": {"question_id": "cuet-phy-ac-circuits-18", "subtopic": "series LCR resonance", "topic_name": "AC Circuits", "bloom_level": "understand", "options": [{"key": "A", "value": "Zero", "is_correct": false}, {"key": "B", "value": "R", "is_correct": true}, {"key": "C", "value": "X_L + X_C", "is_correct": false}, {"key": "D", "value": "√(R² + X_L²)", "is_correct": false}], "elimination_hints": ["Zero impedance would mean infinite current — physically impossible with R present.", "At resonance, X_L = X_C cancel out, leaving only R.", "X_L + X_C is not relevant — the reactive voltages oppose each other (subtract, not add)."]}}]'::jsonb, 'deploy-2026-03-05-b06');

SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-em-ac-circuits", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The resonant frequency of a series LCR circuit is:", "explanation": "At resonance, X_L = X_C, i.e., ωL = 1/(ωC). Solving: ω² = 1/(LC), so ω₀ = 1/√(LC). The resonant frequency f₀ = 1/(2π√(LC)). At this frequency, impedance is minimum and current is maximum.", "correct_answer": "A", "concept_tags": ["resonant-frequency", "LCR-circuit", "formula"], "payload": {"question_id": "cuet-phy-ac-circuits-19", "subtopic": "series LCR resonance", "topic_name": "AC Circuits", "bloom_level": "remember", "options": [{"key": "A", "value": "1/(2π√(LC))", "is_correct": true}, {"key": "B", "value": "2π√(LC)", "is_correct": false}, {"key": "C", "value": "1/(2πLC)", "is_correct": false}, {"key": "D", "value": "√(LC)/(2π)", "is_correct": false}], "elimination_hints": ["f₀ must decrease when L or C increases (larger L or C means lower resonant frequency).", "2π√(LC) increases with L and C — opposite to expected behavior.", "f₀ = ω₀/(2π) = 1/(2π√(LC)). The √ is crucial."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-em-ac-circuits", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A series LCR circuit has L = 1 H, C = 1 μF, and R = 100 Ω. The resonant frequency is approximately:", "explanation": "f₀ = 1/(2π√(LC)) = 1/(2π√(1 × 10⁻⁶)) = 1/(2π × 10⁻³) = 1000/(2π) ≈ 159 Hz.", "correct_answer": "C", "concept_tags": ["resonant-frequency", "numerical-problem", "LCR-circuit"], "payload": {"question_id": "cuet-phy-ac-circuits-20", "subtopic": "series LCR resonance", "topic_name": "AC Circuits", "bloom_level": "apply", "options": [{"key": "A", "value": "50 Hz", "is_correct": false}, {"key": "B", "value": "100 Hz", "is_correct": false}, {"key": "C", "value": "159 Hz", "is_correct": true}, {"key": "D", "value": "1000 Hz", "is_correct": false}], "elimination_hints": ["√(LC) = √(1 × 10⁻⁶) = 10⁻³ s.", "f₀ = 1/(2π × 10⁻³) = 1000/(2π) ≈ 159 Hz.", "1000 Hz would be the answer without the 2π factor."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-em-ac-circuits", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "At resonance in a series LCR circuit, the phase difference between voltage and current is:", "explanation": "At resonance, X_L = X_C, so the net reactance is zero. The circuit is purely resistive, and voltage and current are in phase. tan(φ) = (X_L − X_C)/R = 0, so φ = 0°.", "correct_answer": "A", "concept_tags": ["resonance", "phase-difference", "zero-phase"], "payload": {"question_id": "cuet-phy-ac-circuits-21", "subtopic": "series LCR resonance", "topic_name": "AC Circuits", "bloom_level": "understand", "options": [{"key": "A", "value": "0°", "is_correct": true}, {"key": "B", "value": "90°", "is_correct": false}, {"key": "C", "value": "45°", "is_correct": false}, {"key": "D", "value": "180°", "is_correct": false}], "elimination_hints": ["At resonance the circuit is purely resistive — and in a resistor, V and I are in phase.", "90° occurs in purely reactive circuits (L or C alone).", "The reactive components cancel at resonance, leaving only R."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-em-ac-circuits", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "The quality factor (Q-factor) of a series LCR circuit at resonance is:", "explanation": "The Q-factor measures the sharpness of resonance: Q = ω₀L/R = 1/(ω₀CR) = (1/R)√(L/C). A higher Q means a sharper resonance peak and greater frequency selectivity. Q also equals V_L/V_R or V_C/V_R at resonance.", "correct_answer": "D", "concept_tags": ["quality-factor", "sharpness-of-resonance", "LCR-circuit"], "payload": {"question_id": "cuet-phy-ac-circuits-22", "subtopic": "Q-factor", "topic_name": "AC Circuits", "bloom_level": "remember", "options": [{"key": "A", "value": "R/(ω₀L)", "is_correct": false}, {"key": "B", "value": "ω₀CR", "is_correct": false}, {"key": "C", "value": "R√(L/C)", "is_correct": false}, {"key": "D", "value": "ω₀L/R", "is_correct": true}], "elimination_hints": ["Q should increase when R decreases (sharper resonance), so R must be in the denominator.", "R/(ω₀L) is 1/Q, not Q.", "Q = ω₀L/R = (1/R)√(L/C) — both expressions are equivalent at resonance."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-em-ac-circuits", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "In a series LCR circuit, R = 10 Ω, L = 0.1 H, and C = 10 μF. The Q-factor at resonance is:", "explanation": "Q = (1/R)√(L/C) = (1/10)√(0.1/(10 × 10⁻⁶)) = (1/10)√(10⁴) = (1/10) × 100 = 10.", "correct_answer": "C", "concept_tags": ["quality-factor", "numerical-problem", "resonance"], "payload": {"question_id": "cuet-phy-ac-circuits-23", "subtopic": "Q-factor", "topic_name": "AC Circuits", "bloom_level": "apply", "options": [{"key": "A", "value": "1", "is_correct": false}, {"key": "B", "value": "5", "is_correct": false}, {"key": "C", "value": "10", "is_correct": true}, {"key": "D", "value": "100", "is_correct": false}], "elimination_hints": ["L/C = 0.1/(10⁻⁵) = 10⁴. √(10⁴) = 100.", "Q = 100/R = 100/10 = 10.", "100 would be the answer if R = 1 Ω."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-em-ac-circuits", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The power dissipated in a purely inductive or purely capacitive AC circuit is:", "explanation": "In a purely inductive or purely capacitive circuit, the phase difference between V and I is 90°. Power P = V_rms × I_rms × cosφ = V_rms × I_rms × cos90° = 0. Energy is alternately stored and released, with zero net dissipation per cycle.", "correct_answer": "A", "concept_tags": ["power", "pure-reactance", "zero-power"], "payload": {"question_id": "cuet-phy-ac-circuits-24", "subtopic": "power in AC circuits", "topic_name": "AC Circuits", "bloom_level": "understand", "options": [{"key": "A", "value": "Zero", "is_correct": true}, {"key": "B", "value": "V_rms × I_rms", "is_correct": false}, {"key": "C", "value": "(V_rms × I_rms)/2", "is_correct": false}, {"key": "D", "value": "V_rms²/X", "is_correct": false}], "elimination_hints": ["V_rms × I_rms is the apparent power, not the real (dissipated) power.", "Power factor cosφ = cos90° = 0 for purely reactive circuits.", "Only resistance dissipates power; ideal inductors and capacitors store and return energy."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-em-ac-circuits", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The power factor of an AC circuit is defined as:", "explanation": "Power factor = cosφ = R/Z, where φ is the phase angle between voltage and current. It determines what fraction of apparent power is actually dissipated. Power factor ranges from 0 (purely reactive) to 1 (purely resistive or at resonance).", "correct_answer": "B", "concept_tags": ["power-factor", "cos-phi", "impedance"], "payload": {"question_id": "cuet-phy-ac-circuits-25", "subtopic": "power in AC circuits", "topic_name": "AC Circuits", "bloom_level": "remember", "options": [{"key": "A", "value": "sinφ", "is_correct": false}, {"key": "B", "value": "cosφ", "is_correct": true}, {"key": "C", "value": "tanφ", "is_correct": false}, {"key": "D", "value": "Z/R", "is_correct": false}], "elimination_hints": ["Power = V_rms × I_rms × cosφ, so the factor is cosφ, not sinφ.", "Z/R is always ≥ 1, but power factor must be ≤ 1. It''s R/Z, not Z/R.", "tanφ = (X_L − X_C)/R gives the phase angle relationship, not the power factor."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-em-ac-circuits", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The power factor of a series LCR circuit at resonance is:", "explanation": "At resonance, X_L = X_C, so Z = R. Power factor = R/Z = R/R = 1 (or cosφ = cos0° = 1). The circuit behaves as purely resistive, and maximum power is transferred.", "correct_answer": "D", "concept_tags": ["power-factor", "resonance", "maximum-power"], "payload": {"question_id": "cuet-phy-ac-circuits-26", "subtopic": "power in AC circuits", "topic_name": "AC Circuits", "bloom_level": "understand", "options": [{"key": "A", "value": "0", "is_correct": false}, {"key": "B", "value": "0.5", "is_correct": false}, {"key": "C", "value": "1/√2", "is_correct": false}, {"key": "D", "value": "1", "is_correct": true}], "elimination_hints": ["Power factor 0 means no power dissipation — that''s for purely reactive circuits.", "At resonance, the circuit is purely resistive, giving the maximum possible power factor.", "cosφ = R/Z = R/R = 1 at resonance."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-em-ac-circuits", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "In a series LR circuit, R = 30 Ω and X_L = 40 Ω. The impedance and power factor are:", "explanation": "Z = √(R² + X_L²) = √(900 + 1600) = √2500 = 50 Ω. Power factor = cosφ = R/Z = 30/50 = 0.6.", "correct_answer": "B", "concept_tags": ["impedance", "power-factor", "LR-circuit"], "payload": {"question_id": "cuet-phy-ac-circuits-27", "subtopic": "series LR circuit", "topic_name": "AC Circuits", "bloom_level": "apply", "options": [{"key": "A", "value": "Z = 70 Ω, cosφ = 0.43", "is_correct": false}, {"key": "B", "value": "Z = 50 Ω, cosφ = 0.6", "is_correct": true}, {"key": "C", "value": "Z = 50 Ω, cosφ = 0.8", "is_correct": false}, {"key": "D", "value": "Z = 10 Ω, cosφ = 0.3", "is_correct": false}], "elimination_hints": ["70 Ω = R + X_L — but impedances don''t add linearly (they add as vectors).", "Z = √(30² + 40²) = √(2500) = 50 Ω (a 3-4-5 right triangle scaled by 10).", "cosφ = R/Z = 30/50 = 0.6, not 40/50 = 0.8."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-em-ac-circuits", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The average power dissipated in an AC circuit is:", "explanation": "Average power P = V_rms × I_rms × cosφ, where cosφ is the power factor. This is also called true power or real power. Only the resistive component of the circuit dissipates power.", "correct_answer": "C", "concept_tags": ["average-power", "power-factor", "AC-power"], "payload": {"question_id": "cuet-phy-ac-circuits-28", "subtopic": "power in AC circuits", "topic_name": "AC Circuits", "bloom_level": "remember", "options": [{"key": "A", "value": "V_rms × I_rms", "is_correct": false}, {"key": "B", "value": "V₀ × I₀", "is_correct": false}, {"key": "C", "value": "V_rms × I_rms × cosφ", "is_correct": true}, {"key": "D", "value": "V_rms × I_rms × sinφ", "is_correct": false}], "elimination_hints": ["V_rms × I_rms is the apparent power (VA), not the real power (W).", "V₀ × I₀ is neither the apparent nor the real power.", "sinφ gives the reactive power component, not the dissipated power."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-em-ac-circuits", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The quantity V_rms × I_rms in an AC circuit is called:", "explanation": "V_rms × I_rms is called apparent power (measured in volt-amperes, VA). The real power is P = V_rms × I_rms × cosφ. The ratio of real power to apparent power is the power factor.", "correct_answer": "B", "concept_tags": ["apparent-power", "volt-ampere", "power-terminology"], "payload": {"question_id": "cuet-phy-ac-circuits-29", "subtopic": "power in AC circuits", "topic_name": "AC Circuits", "bloom_level": "remember", "options": [{"key": "A", "value": "Real power", "is_correct": false}, {"key": "B", "value": "Apparent power", "is_correct": true}, {"key": "C", "value": "Power factor", "is_correct": false}, {"key": "D", "value": "Reactive power", "is_correct": false}], "elimination_hints": ["Real power includes the cosφ factor: P = V_rms × I_rms × cosφ.", "Power factor is cosφ (dimensionless), not a power quantity.", "Reactive power is V_rms × I_rms × sinφ, measured in VAR."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-em-ac-circuits", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "A transformer works on the principle of:", "explanation": "A transformer works on the principle of mutual induction. An alternating current in the primary coil creates a changing magnetic flux, which links with the secondary coil and induces an EMF in it. Transformers only work with AC, not DC.", "correct_answer": "C", "concept_tags": ["transformer", "mutual-induction", "working-principle"], "payload": {"question_id": "cuet-phy-ac-circuits-30", "subtopic": "transformer", "topic_name": "AC Circuits", "bloom_level": "remember", "options": [{"key": "A", "value": "Self-induction", "is_correct": false}, {"key": "B", "value": "Electromagnetic force", "is_correct": false}, {"key": "C", "value": "Mutual induction", "is_correct": true}, {"key": "D", "value": "Electrostatic induction", "is_correct": false}], "elimination_hints": ["Self-induction involves a single coil, but a transformer has two separate coils.", "Electrostatic induction involves charges, not changing magnetic flux.", "The primary coil''s changing flux induces EMF in the secondary — this is mutual induction."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-em-ac-circuits", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "In an ideal transformer, the ratio of secondary EMF to primary EMF equals:", "explanation": "For an ideal transformer, ε_s/ε_p = N_s/N_p, where N_s and N_p are the number of turns in the secondary and primary coils respectively. This is the turns ratio. A step-up transformer has N_s > N_p, and a step-down transformer has N_s < N_p.", "correct_answer": "A", "concept_tags": ["transformer", "turns-ratio", "EMF-ratio"], "payload": {"question_id": "cuet-phy-ac-circuits-31", "subtopic": "transformer", "topic_name": "AC Circuits", "bloom_level": "remember", "options": [{"key": "A", "value": "N_s/N_p", "is_correct": true}, {"key": "B", "value": "N_p/N_s", "is_correct": false}, {"key": "C", "value": "(N_s/N_p)²", "is_correct": false}, {"key": "D", "value": "√(N_s/N_p)", "is_correct": false}], "elimination_hints": ["N_p/N_s is the inverse of the turns ratio (ε_p/ε_s, not ε_s/ε_p).", "(N_s/N_p)² relates to impedance transformation, not voltage transformation.", "EMF is proportional to N (more turns = more flux linkage = more EMF)."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-em-ac-circuits", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A step-up transformer has:", "explanation": "A step-up transformer increases voltage: V_s > V_p. This requires N_s > N_p (more turns in secondary). By energy conservation (for ideal transformer), P_s = P_p, so I_s < I_p — the current decreases when voltage increases.", "correct_answer": "B", "concept_tags": ["step-up-transformer", "turns-ratio", "voltage-current"], "payload": {"question_id": "cuet-phy-ac-circuits-32", "subtopic": "transformer", "topic_name": "AC Circuits", "bloom_level": "understand", "options": [{"key": "A", "value": "N_s < N_p", "is_correct": false}, {"key": "B", "value": "N_s > N_p", "is_correct": true}, {"key": "C", "value": "N_s = N_p", "is_correct": false}, {"key": "D", "value": "I_s > I_p", "is_correct": false}], "elimination_hints": ["N_s < N_p is a step-down transformer (voltage decreases).", "N_s = N_p gives a 1:1 isolation transformer.", "In a step-up transformer, voltage increases but current decreases (power is conserved)."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-em-ac-circuits", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A transformer has 200 turns in the primary and 1000 turns in the secondary. If the primary voltage is 220 V, the secondary voltage is:", "explanation": "V_s/V_p = N_s/N_p. V_s = V_p × (N_s/N_p) = 220 × (1000/200) = 220 × 5 = 1100 V.", "correct_answer": "D", "concept_tags": ["transformer", "turns-ratio", "numerical-problem"], "payload": {"question_id": "cuet-phy-ac-circuits-33", "subtopic": "transformer", "topic_name": "AC Circuits", "bloom_level": "apply", "options": [{"key": "A", "value": "44 V", "is_correct": false}, {"key": "B", "value": "220 V", "is_correct": false}, {"key": "C", "value": "550 V", "is_correct": false}, {"key": "D", "value": "1100 V", "is_correct": true}], "elimination_hints": ["Turns ratio = 1000/200 = 5. This is a step-up transformer.", "V_s = 220 × 5 = 1100 V.", "44 V would result from using N_p/N_s (step-down) instead of N_s/N_p."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-em-ac-circuits", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "An ideal transformer has a primary voltage of 240 V and delivers 12 V to a load that draws 2 A. The primary current is:", "explanation": "For an ideal transformer, P_p = P_s. So V_p × I_p = V_s × I_s. I_p = V_s × I_s / V_p = 12 × 2 / 240 = 24/240 = 0.1 A.", "correct_answer": "A", "concept_tags": ["transformer", "power-conservation", "numerical-problem"], "payload": {"question_id": "cuet-phy-ac-circuits-34", "subtopic": "transformer", "topic_name": "AC Circuits", "bloom_level": "apply", "options": [{"key": "A", "value": "0.1 A", "is_correct": true}, {"key": "B", "value": "0.5 A", "is_correct": false}, {"key": "C", "value": "2 A", "is_correct": false}, {"key": "D", "value": "40 A", "is_correct": false}], "elimination_hints": ["Power conservation: V_p × I_p = V_s × I_s = 12 × 2 = 24 W.", "I_p = 24/240 = 0.1 A.", "Since this is a step-down transformer (240 V → 12 V), the primary current must be less than the secondary current."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-em-ac-circuits", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "Energy losses in a transformer can be reduced by:", "explanation": "Major transformer losses include: (1) Eddy current losses — reduced by using laminated iron core, (2) Hysteresis losses — reduced by using soft iron (low coercivity), (3) Copper losses (I²R) — reduced by using thick copper wires, (4) Flux leakage — reduced by winding coils over each other.", "correct_answer": "D", "concept_tags": ["transformer", "energy-losses", "lamination"], "payload": {"question_id": "cuet-phy-ac-circuits-35", "subtopic": "transformer losses", "topic_name": "AC Circuits", "bloom_level": "understand", "options": [{"key": "A", "value": "Using a solid iron core", "is_correct": false}, {"key": "B", "value": "Using thin wires for windings", "is_correct": false}, {"key": "C", "value": "Keeping primary and secondary coils far apart", "is_correct": false}, {"key": "D", "value": "Using a laminated soft iron core with thick copper windings", "is_correct": true}], "elimination_hints": ["Solid iron cores have large eddy currents — lamination reduces them.", "Thin wires have high resistance, increasing I²R (copper) losses.", "Keeping coils far apart increases flux leakage — they should be close together."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-em-ac-circuits", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A series LCR circuit has R = 20 Ω, L = 0.2 H, C = 50 μF and is connected to a 220 V, 50 Hz source. The current in the circuit is approximately:", "explanation": "X_L = 2πfL = 2π × 50 × 0.2 = 20π ≈ 62.8 Ω. X_C = 1/(2πfC) = 1/(2π × 50 × 50 × 10⁻⁶) = 1/(5π × 10⁻³) = 200/π ≈ 63.7 Ω. X_L − X_C ≈ 62.8 − 63.7 = −0.9 Ω. Z = √(20² + 0.81) ≈ √(400.81) ≈ 20.02 Ω. I = V/Z = 220/20.02 ≈ 11 A.", "correct_answer": "C", "concept_tags": ["LCR-circuit", "impedance", "numerical-problem"], "payload": {"question_id": "cuet-phy-ac-circuits-36", "subtopic": "series LCR circuit", "topic_name": "AC Circuits", "bloom_level": "apply", "options": [{"key": "A", "value": "2.5 A", "is_correct": false}, {"key": "B", "value": "5 A", "is_correct": false}, {"key": "C", "value": "11 A", "is_correct": true}, {"key": "D", "value": "22 A", "is_correct": false}], "elimination_hints": ["X_L ≈ X_C ≈ 63 Ω, so they nearly cancel — the circuit is near resonance.", "Near resonance, Z ≈ R = 20 Ω, so I ≈ 220/20 = 11 A.", "22 A would imply Z ≈ 10 Ω, which is less than R alone — impossible."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-em-ac-circuits", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "In a series LCR circuit, if X_L > X_C, the circuit is:", "explanation": "When X_L > X_C, the net reactance is inductive (positive). The current lags behind the voltage. The phase angle φ = tan⁻¹[(X_L − X_C)/R] is positive, meaning the circuit behaves inductively.", "correct_answer": "A", "concept_tags": ["LCR-circuit", "inductive-behavior", "phase-angle"], "payload": {"question_id": "cuet-phy-ac-circuits-37", "subtopic": "series LCR circuit", "topic_name": "AC Circuits", "bloom_level": "understand", "options": [{"key": "A", "value": "Inductive (current lags voltage)", "is_correct": true}, {"key": "B", "value": "Capacitive (current leads voltage)", "is_correct": false}, {"key": "C", "value": "Resistive (current in phase with voltage)", "is_correct": false}, {"key": "D", "value": "At resonance", "is_correct": false}], "elimination_hints": ["X_L > X_C means inductive reactance dominates — the circuit behaves like an inductor.", "Capacitive behavior requires X_C > X_L.", "At resonance, X_L = X_C exactly."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-em-ac-circuits", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A transformer cannot work with DC because:", "explanation": "A transformer requires changing magnetic flux to induce EMF in the secondary (Faraday''s law). DC produces a constant current, hence a constant magnetic flux, so dΦ/dt = 0 and no EMF is induced in the secondary. Additionally, DC can saturate the core.", "correct_answer": "B", "concept_tags": ["transformer", "DC-limitation", "flux-change"], "payload": {"question_id": "cuet-phy-ac-circuits-38", "subtopic": "transformer", "topic_name": "AC Circuits", "bloom_level": "understand", "options": [{"key": "A", "value": "DC produces too much current", "is_correct": false}, {"key": "B", "value": "DC produces a constant flux which does not induce EMF in the secondary", "is_correct": true}, {"key": "C", "value": "DC cannot flow through the primary coil", "is_correct": false}, {"key": "D", "value": "DC destroys the core material", "is_correct": false}], "elimination_hints": ["DC can certainly flow through the primary coil (it''s just a wire).", "The problem is not the amount of current but the lack of changing flux.", "Faraday''s law: ε = −dΦ/dt. If Φ is constant (DC), ε = 0 in the secondary."]}}]'::jsonb, 'deploy-2026-03-05-b06');

SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-em-ac-circuits", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "In long-distance power transmission, electrical energy is transmitted at high voltage and low current because:", "explanation": "Power loss in transmission lines = I²R, where R is the line resistance. By using high voltage (via step-up transformer), the current is reduced for the same power (P = VI). Lower current means much less I²R power loss. At the receiving end, a step-down transformer reduces the voltage for consumer use.", "correct_answer": "D", "concept_tags": ["power-transmission", "high-voltage", "I²R-losses"], "payload": {"question_id": "cuet-phy-ac-circuits-39", "subtopic": "power transmission", "topic_name": "AC Circuits", "bloom_level": "understand", "options": [{"key": "A", "value": "High voltage is safer for transmission", "is_correct": false}, {"key": "B", "value": "High voltage reduces the cost of cables", "is_correct": false}, {"key": "C", "value": "Low current increases the power delivered", "is_correct": false}, {"key": "D", "value": "Low current reduces I²R transmission losses", "is_correct": true}], "elimination_hints": ["High voltage is actually more dangerous, not safer.", "Power delivered P = VI remains the same; only the losses change.", "Transmission losses depend on I²R — reducing I drastically reduces losses."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-em-ac-circuits", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "An AC source of 220 V, 50 Hz is connected to a series combination of a 10 Ω resistance and a capacitor of 100/(π) μF. The power dissipated in the circuit is:", "explanation": "X_C = 1/(2πfC) = 1/(2π × 50 × 100/(π) × 10⁻⁶) = 1/(2 × 50 × 100 × 10⁻⁶) = 1/(10⁻² ) = 100 Ω. Z = √(R² + X_C²) = √(100 + 10000) = √10100 ≈ 100.5 Ω. I_rms = 220/100.5 ≈ 2.19 A. Power = I²R = (2.19)² × 10 ≈ 48 W. Alternatively, P = V²R/Z² = 220² × 10/10100 ≈ 484000/10100 ≈ 48 W.", "correct_answer": "B", "concept_tags": ["RC-circuit", "power-dissipation", "numerical-problem"], "payload": {"question_id": "cuet-phy-ac-circuits-40", "subtopic": "power in AC circuits", "topic_name": "AC Circuits", "bloom_level": "apply", "options": [{"key": "A", "value": "24 W", "is_correct": false}, {"key": "B", "value": "48 W", "is_correct": true}, {"key": "C", "value": "484 W", "is_correct": false}, {"key": "D", "value": "4840 W", "is_correct": false}], "elimination_hints": ["X_C = 100 Ω (much larger than R = 10 Ω), so Z ≈ 100.5 Ω.", "484 W = V²/R — this ignores the capacitive reactance entirely.", "P = V²R/Z² = (220)² × 10 / (100.5)² ≈ 48 W."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "In an LC oscillating circuit, the total energy is:", "explanation": "In an ideal LC circuit, energy oscillates between the inductor (magnetic energy ½LI²) and the capacitor (electric energy ½CV²). The total energy remains constant as there is no resistance to dissipate energy. At any instant, U_total = ½LI² + ½CV² = ½CV₀² = ½LI₀² = constant.", "correct_answer": "C", "concept_tags": ["LC-oscillation", "energy-conservation", "electromagnetic-oscillation"], "payload": {"question_id": "cuet-phy-ac-adv-01", "subtopic": "LC oscillations", "topic_name": "AC Circuits — Advanced", "bloom_level": "remember", "options": [{"key": "A", "value": "Stored only in the inductor", "is_correct": false}, {"key": "B", "value": "Stored only in the capacitor", "is_correct": false}, {"key": "C", "value": "Constant and shared between L and C", "is_correct": true}, {"key": "D", "value": "Continuously dissipated as heat", "is_correct": false}], "elimination_hints": ["Energy is stored in the inductor only at the instant of maximum current.", "Energy is stored in the capacitor only at the instant of maximum charge.", "There is no resistance in an ideal LC circuit, so no heat is dissipated."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The frequency of oscillation in an ideal LC circuit with inductance L and capacitance C is:", "explanation": "The angular frequency of LC oscillation is ω = 1/√(LC), so the frequency f = ω/(2π) = 1/(2π√(LC)). This is analogous to SHM of a spring-mass system where ω = √(k/m).", "correct_answer": "B", "concept_tags": ["LC-oscillation", "frequency", "angular-frequency"], "payload": {"question_id": "cuet-phy-ac-adv-02", "subtopic": "LC oscillations", "topic_name": "AC Circuits — Advanced", "bloom_level": "remember", "options": [{"key": "A", "value": "1/(2π)√(L/C)", "is_correct": false}, {"key": "B", "value": "1/(2π√(LC))", "is_correct": true}, {"key": "C", "value": "2π√(LC)", "is_correct": false}, {"key": "D", "value": "1/(2πLC)", "is_correct": false}], "elimination_hints": ["√(L/C) has dimensions of impedance, not frequency.", "2π√(LC) has dimensions of time (the time period T), not frequency.", "1/(2πLC) does not have the correct dimensions of frequency."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "In an LC circuit, the charge on the capacitor oscillates as q = q₀ cos(ωt). The current in the circuit is:", "explanation": "Current I = dq/dt = d(q₀ cos(ωt))/dt = −q₀ω sin(ωt). The magnitude of maximum current I₀ = q₀ω. The current leads the charge by π/2 (90°). When charge is maximum, current is zero and vice versa.", "correct_answer": "A", "concept_tags": ["LC-oscillation", "current", "differentiation", "phase"], "payload": {"question_id": "cuet-phy-ac-adv-03", "subtopic": "LC oscillations", "topic_name": "AC Circuits — Advanced", "bloom_level": "apply", "options": [{"key": "A", "value": "−q₀ω sin(ωt)", "is_correct": true}, {"key": "B", "value": "q₀ω sin(ωt)", "is_correct": false}, {"key": "C", "value": "q₀ω cos(ωt)", "is_correct": false}, {"key": "D", "value": "−q₀ω cos(ωt)", "is_correct": false}], "elimination_hints": ["Current is the derivative of charge, not the same function.", "d(cos(ωt))/dt = −ω sin(ωt), so the negative sign is essential.", "cos differentiates to −sin, not to cos or +sin."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The LC oscillation is analogous to the mechanical oscillation of a spring-mass system. In this analogy, the inductance L corresponds to:", "explanation": "In the LC-SHM analogy: inductance L ↔ mass m, capacitance C ↔ 1/k (inverse of spring constant), charge q ↔ displacement x, current I ↔ velocity v, ½LI² ↔ ½mv² (kinetic energy), ½q²/C ↔ ½kx² (potential energy).", "correct_answer": "B", "concept_tags": ["LC-oscillation", "SHM-analogy", "inductance"], "payload": {"question_id": "cuet-phy-ac-adv-04", "subtopic": "LC oscillations — SHM analogy", "topic_name": "AC Circuits — Advanced", "bloom_level": "understand", "options": [{"key": "A", "value": "Spring constant k", "is_correct": false}, {"key": "B", "value": "Mass m", "is_correct": true}, {"key": "C", "value": "Displacement x", "is_correct": false}, {"key": "D", "value": "Velocity v", "is_correct": false}], "elimination_hints": ["Spring constant k corresponds to 1/C, not L.", "Displacement x corresponds to charge q.", "L appears in ½LI² which is analogous to ½mv², so L ↔ m."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "In an LC oscillating circuit with inductance L = 0.5 H and capacitance C = 20 μF, the angular frequency of oscillation is:", "explanation": "ω = 1/√(LC) = 1/√(0.5 × 20 × 10⁻⁶) = 1/√(10⁻⁵) = 1/(10⁻²·⁵) = 10²·⁵ = √(10⁵) = √(100000) ≈ 316.2 rad/s. Rounding: ω = 100√10 ≈ 316 rad/s.", "correct_answer": "C", "concept_tags": ["LC-oscillation", "angular-frequency", "numerical"], "payload": {"question_id": "cuet-phy-ac-adv-05", "subtopic": "LC oscillations", "topic_name": "AC Circuits — Advanced", "bloom_level": "apply", "options": [{"key": "A", "value": "100 rad/s", "is_correct": false}, {"key": "B", "value": "200 rad/s", "is_correct": false}, {"key": "C", "value": "100√10 rad/s", "is_correct": true}, {"key": "D", "value": "1000 rad/s", "is_correct": false}], "elimination_hints": ["LC = 0.5 × 20 × 10⁻⁶ = 10⁻⁵, so √(LC) = 10⁻²·⁵.", "1/10⁻²·⁵ = 10²·⁵ = √(10⁵) = 100√10 ≈ 316 rad/s.", "100 rad/s and 1000 rad/s are common traps from unit errors."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "When the current in an LC circuit is maximum, the energy stored in the inductor is:", "explanation": "When current is maximum (I = I₀), all energy is stored in the inductor as magnetic energy: U_L = ½LI₀². At this instant the capacitor is fully discharged (q = 0), so U_C = 0. The total energy equals ½LI₀².", "correct_answer": "D", "concept_tags": ["LC-oscillation", "magnetic-energy", "energy-transfer"], "payload": {"question_id": "cuet-phy-ac-adv-06", "subtopic": "LC oscillations", "topic_name": "AC Circuits — Advanced", "bloom_level": "understand", "options": [{"key": "A", "value": "Zero", "is_correct": false}, {"key": "B", "value": "Half of the total energy", "is_correct": false}, {"key": "C", "value": "One-fourth of the total energy", "is_correct": false}, {"key": "D", "value": "Equal to the total energy", "is_correct": true}], "elimination_hints": ["Zero energy in the inductor occurs when current is zero, not maximum.", "Energy is equally shared when I = I₀/√2, not at maximum current.", "At maximum current, the capacitor is fully discharged — all energy is in L."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The power factor of a purely resistive AC circuit is:", "explanation": "Power factor = cos φ, where φ is the phase difference between voltage and current. In a purely resistive circuit, voltage and current are in phase (φ = 0°), so cos 0° = 1. Maximum power is dissipated.", "correct_answer": "A", "concept_tags": ["power-factor", "resistive-circuit", "phase-angle"], "payload": {"question_id": "cuet-phy-ac-adv-07", "subtopic": "power factor", "topic_name": "AC Circuits — Advanced", "bloom_level": "remember", "options": [{"key": "A", "value": "1", "is_correct": true}, {"key": "B", "value": "0", "is_correct": false}, {"key": "C", "value": "0.5", "is_correct": false}, {"key": "D", "value": "∞", "is_correct": false}], "elimination_hints": ["Power factor = 0 for purely reactive (L or C) circuits, not resistive.", "cos φ always lies between 0 and 1; it cannot be ∞.", "In a purely resistive circuit, φ = 0° and cos 0° = 1."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The wattless component of current in an AC circuit is:", "explanation": "In an AC circuit, the current has two components: (1) I cos φ — the active or wattful component (in phase with voltage, responsible for power dissipation), and (2) I sin φ — the reactive or wattless component (90° out of phase with voltage, contributes zero average power).", "correct_answer": "B", "concept_tags": ["wattless-current", "reactive-component", "power-factor"], "payload": {"question_id": "cuet-phy-ac-adv-08", "subtopic": "wattless current", "topic_name": "AC Circuits — Advanced", "bloom_level": "remember", "options": [{"key": "A", "value": "I cos φ", "is_correct": false}, {"key": "B", "value": "I sin φ", "is_correct": true}, {"key": "C", "value": "I tan φ", "is_correct": false}, {"key": "D", "value": "I/cos φ", "is_correct": false}], "elimination_hints": ["I cos φ is the wattful (active) component, not the wattless component.", "I tan φ and I/cos φ do not represent standard AC current components.", "The wattless component is perpendicular to voltage — it involves sin φ."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "In a purely inductive AC circuit, the wattless component of current is:", "explanation": "In a purely inductive circuit, the phase angle φ = 90° (current lags voltage by π/2). The wattless component = I sin φ = I sin 90° = I (the entire current). The active component = I cos 90° = 0. Hence no power is dissipated — all current is wattless.", "correct_answer": "C", "concept_tags": ["wattless-current", "inductive-circuit", "phase-angle"], "payload": {"question_id": "cuet-phy-ac-adv-09", "subtopic": "wattless current", "topic_name": "AC Circuits — Advanced", "bloom_level": "apply", "options": [{"key": "A", "value": "Zero", "is_correct": false}, {"key": "B", "value": "I/√2", "is_correct": false}, {"key": "C", "value": "I (total current)", "is_correct": true}, {"key": "D", "value": "I/2", "is_correct": false}], "elimination_hints": ["Zero wattless current occurs in a purely resistive circuit (φ = 0).", "I/√2 would occur when φ = 45°, not 90°.", "For purely inductive circuit φ = 90°, so sin 90° = 1 → entire current is wattless."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "An AC circuit has an impedance of 50 Ω and the voltage leads the current by 60°. The wattful and wattless components of a 4 A current are:", "explanation": "Wattful component = I cos φ = 4 × cos 60° = 4 × 0.5 = 2 A. Wattless component = I sin φ = 4 × sin 60° = 4 × (√3/2) = 2√3 A. The power dissipated = V_rms × I × cos φ = 50 × 4 × 4 × 0.5 = 400 W (or equivalently I²R where R = Z cos φ = 25 Ω).", "correct_answer": "B", "concept_tags": ["wattless-current", "wattful-current", "numerical", "impedance"], "payload": {"question_id": "cuet-phy-ac-adv-10", "subtopic": "wattless current", "topic_name": "AC Circuits — Advanced", "bloom_level": "apply", "options": [{"key": "A", "value": "2√3 A and 2 A", "is_correct": false}, {"key": "B", "value": "2 A and 2√3 A", "is_correct": true}, {"key": "C", "value": "4 A and 0 A", "is_correct": false}, {"key": "D", "value": "0 A and 4 A", "is_correct": false}], "elimination_hints": ["Option A swaps the wattful and wattless values.", "4 A and 0 A would mean φ = 0° (purely resistive), but φ = 60°.", "cos 60° = 0.5, so wattful = 4 × 0.5 = 2 A; sin 60° = √3/2, so wattless = 2√3 A."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The power dissipated in a purely capacitive AC circuit is:", "explanation": "In a purely capacitive circuit, the phase angle φ = 90° (current leads voltage by π/2). Average power P = V_rms × I_rms × cos φ = V_rms × I_rms × cos 90° = 0. Energy is alternately stored in and returned from the capacitor''s electric field.", "correct_answer": "A", "concept_tags": ["power", "capacitive-circuit", "wattless"], "payload": {"question_id": "cuet-phy-ac-adv-11", "subtopic": "power in reactive circuits", "topic_name": "AC Circuits — Advanced", "bloom_level": "remember", "options": [{"key": "A", "value": "Zero", "is_correct": true}, {"key": "B", "value": "V_rms × I_rms", "is_correct": false}, {"key": "C", "value": "½ V_rms × I_rms", "is_correct": false}, {"key": "D", "value": "V_rms²/X_C", "is_correct": false}], "elimination_hints": ["V_rms × I_rms is the apparent power, not the true (real) power.", "V_rms²/X_C gives the reactive power (VAR), not the real power (W).", "cos 90° = 0, so no real power is dissipated in a purely capacitive circuit."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The quality factor (Q-factor) of a series LCR circuit at resonance is given by:", "explanation": "Q-factor = ω₀L/R = 1/(ω₀CR) = (1/R)√(L/C). It measures the sharpness of resonance — a higher Q means a narrower resonance peak. Q also equals the ratio of voltage across L (or C) to the applied voltage at resonance.", "correct_answer": "D", "concept_tags": ["Q-factor", "resonance", "LCR-circuit", "sharpness"], "payload": {"question_id": "cuet-phy-ac-adv-12", "subtopic": "Q-factor and sharpness of resonance", "topic_name": "AC Circuits — Advanced", "bloom_level": "remember", "options": [{"key": "A", "value": "R/(ω₀L)", "is_correct": false}, {"key": "B", "value": "ω₀CR", "is_correct": false}, {"key": "C", "value": "R√(L/C)", "is_correct": false}, {"key": "D", "value": "(1/R)√(L/C)", "is_correct": true}], "elimination_hints": ["R/(ω₀L) is 1/Q, the inverse of the quality factor.", "ω₀CR is also 1/Q — inverting the correct formula.", "Q = ω₀L/R = (1/R)√(L/C). Higher L/C ratio and lower R give higher Q."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A series LCR circuit has L = 10 mH, C = 1 μF, and R = 10 Ω at resonance. The Q-factor of the circuit is:", "explanation": "Q = (1/R)√(L/C) = (1/10)√(10 × 10⁻³/(1 × 10⁻⁶)) = (1/10)√(10⁴) = (1/10) × 100 = 10. Alternatively, ω₀ = 1/√(LC) = 1/√(10⁻⁸) = 10⁴ rad/s, and Q = ω₀L/R = 10⁴ × 10⁻² / 10 = 10.", "correct_answer": "C", "concept_tags": ["Q-factor", "numerical", "LCR-circuit"], "payload": {"question_id": "cuet-phy-ac-adv-13", "subtopic": "Q-factor and sharpness of resonance", "topic_name": "AC Circuits — Advanced", "bloom_level": "apply", "options": [{"key": "A", "value": "1", "is_correct": false}, {"key": "B", "value": "5", "is_correct": false}, {"key": "C", "value": "10", "is_correct": true}, {"key": "D", "value": "100", "is_correct": false}], "elimination_hints": ["√(L/C) = √(10⁻²/10⁻⁶) = √(10⁴) = 100.", "Q = 100/R = 100/10 = 10.", "100 would be the voltage magnification factor times R, not Q itself."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The bandwidth (Δω) of a series LCR resonant circuit is given by:", "explanation": "Bandwidth Δω = R/L. It is the range of angular frequencies around resonance for which the power is at least half the maximum power (half-power points). A higher Q-factor means smaller bandwidth: Δω = ω₀/Q = R/L.", "correct_answer": "A", "concept_tags": ["bandwidth", "resonance", "LCR-circuit", "half-power"], "payload": {"question_id": "cuet-phy-ac-adv-14", "subtopic": "Q-factor and sharpness of resonance", "topic_name": "AC Circuits — Advanced", "bloom_level": "remember", "options": [{"key": "A", "value": "R/L", "is_correct": true}, {"key": "B", "value": "L/R", "is_correct": false}, {"key": "C", "value": "1/√(LC)", "is_correct": false}, {"key": "D", "value": "R/C", "is_correct": false}], "elimination_hints": ["L/R is the time constant of an LR circuit, not bandwidth.", "1/√(LC) is the resonant frequency ω₀, not the bandwidth.", "Bandwidth = ω₀/Q = (1/√(LC))/(ω₀L/R) = R/L."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "In a series LCR circuit, L = 0.1 H, C = 10 μF, and R = 20 Ω. The bandwidth and Q-factor of the circuit are:", "explanation": "Bandwidth Δω = R/L = 20/0.1 = 200 rad/s. Resonant frequency ω₀ = 1/√(LC) = 1/√(0.1 × 10 × 10⁻⁶) = 1/√(10⁻⁶) = 1000 rad/s. Q = ω₀/Δω = 1000/200 = 5. Alternatively, Q = ω₀L/R = 1000 × 0.1/20 = 5.", "correct_answer": "B", "concept_tags": ["bandwidth", "Q-factor", "numerical", "resonance"], "payload": {"question_id": "cuet-phy-ac-adv-15", "subtopic": "Q-factor and sharpness of resonance", "topic_name": "AC Circuits — Advanced", "bloom_level": "apply", "options": [{"key": "A", "value": "100 rad/s and 10", "is_correct": false}, {"key": "B", "value": "200 rad/s and 5", "is_correct": true}, {"key": "C", "value": "200 rad/s and 10", "is_correct": false}, {"key": "D", "value": "500 rad/s and 2", "is_correct": false}], "elimination_hints": ["Δω = R/L = 20/0.1 = 200, so options with 100 or 500 are wrong.", "Q = ω₀L/R = 1000 × 0.1 / 20 = 5.", "Options with Q = 10 use ω₀ = 1000 but divide by R = 100 (wrong R)."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "At resonance in a series LCR circuit, the voltage across the capacitor is Q times the applied voltage. If Q = 20 and the applied RMS voltage is 10 V, the voltage across the capacitor is:", "explanation": "At resonance, V_C = Q × V_applied = 20 × 10 = 200 V. This is because at resonance, X_L = X_C, and the current I = V/R. Voltage across C = IX_C = (V/R)(ω₀L) = V × (ω₀L/R) = VQ. The voltage across L also equals 200 V, and V_L and V_C cancel each other.", "correct_answer": "D", "concept_tags": ["Q-factor", "voltage-magnification", "resonance", "numerical"], "payload": {"question_id": "cuet-phy-ac-adv-16", "subtopic": "Q-factor and sharpness of resonance", "topic_name": "AC Circuits — Advanced", "bloom_level": "apply", "options": [{"key": "A", "value": "10 V", "is_correct": false}, {"key": "B", "value": "20 V", "is_correct": false}, {"key": "C", "value": "100 V", "is_correct": false}, {"key": "D", "value": "200 V", "is_correct": true}], "elimination_hints": ["10 V is the applied voltage, not the amplified voltage across C.", "Q-factor acts as a voltage amplification factor at resonance.", "V_C = Q × V = 20 × 10 = 200 V."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The average power consumed in an AC circuit is given by:", "explanation": "Average power P = V_rms × I_rms × cos φ, where cos φ is the power factor. This is also written as P = I²_rms × R. The term V_rms × I_rms is the apparent power, and cos φ converts it to the actual (real) power dissipated.", "correct_answer": "C", "concept_tags": ["average-power", "power-factor", "real-power"], "payload": {"question_id": "cuet-phy-ac-adv-17", "subtopic": "power in AC circuits", "topic_name": "AC Circuits — Advanced", "bloom_level": "remember", "options": [{"key": "A", "value": "V_rms × I_rms", "is_correct": false}, {"key": "B", "value": "V_rms × I_rms × sin φ", "is_correct": false}, {"key": "C", "value": "V_rms × I_rms × cos φ", "is_correct": true}, {"key": "D", "value": "V_rms × I_rms × tan φ", "is_correct": false}], "elimination_hints": ["V_rms × I_rms is the apparent power (VA), not the real power (W).", "sin φ gives the reactive component, not the power-dissipating component.", "Only the in-phase component (cos φ) contributes to real power dissipation."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The power factor of a series LCR circuit at resonance is:", "explanation": "At resonance, X_L = X_C, so the net reactance is zero. The impedance Z = R (purely resistive). The phase angle φ = tan⁻¹((X_L − X_C)/R) = tan⁻¹(0) = 0°. Therefore, power factor = cos 0° = 1. Maximum power is transferred at resonance.", "correct_answer": "A", "concept_tags": ["power-factor", "resonance", "LCR-circuit"], "payload": {"question_id": "cuet-phy-ac-adv-18", "subtopic": "power factor", "topic_name": "AC Circuits — Advanced", "bloom_level": "remember", "options": [{"key": "A", "value": "1", "is_correct": true}, {"key": "B", "value": "0", "is_correct": false}, {"key": "C", "value": "0.5", "is_correct": false}, {"key": "D", "value": "1/√2", "is_correct": false}], "elimination_hints": ["Power factor = 0 in purely reactive circuits, not at resonance.", "At resonance the circuit is purely resistive — φ = 0° → cos φ = 1.", "Power factor = 1 means maximum power transfer."]}}]'::jsonb, 'deploy-2026-03-05-b06');

SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A power station delivers 500 kW of power at 10,000 V to a factory through cables of total resistance 4 Ω. The power loss in transmission is:", "explanation": "Current I = P/V = 500 × 10³/10⁴ = 50 A. Power loss = I²R = 50² × 4 = 2500 × 4 = 10,000 W = 10 kW. The percentage loss = (10/500) × 100 = 2%. This shows why high-voltage transmission reduces losses — the current is smaller for the same power.", "correct_answer": "B", "concept_tags": ["power-transmission", "transmission-loss", "numerical"], "payload": {"question_id": "cuet-phy-ac-adv-19", "subtopic": "power transmission", "topic_name": "AC Circuits — Advanced", "bloom_level": "apply", "options": [{"key": "A", "value": "5 kW", "is_correct": false}, {"key": "B", "value": "10 kW", "is_correct": true}, {"key": "C", "value": "20 kW", "is_correct": false}, {"key": "D", "value": "50 kW", "is_correct": false}], "elimination_hints": ["I = P/V = 500000/10000 = 50 A.", "Power loss = I²R = 2500 × 4 = 10000 W = 10 kW.", "50 kW would require I²R = 50000, which doesn''t match these values."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "If the transmission voltage is doubled, the power loss in the cables becomes:", "explanation": "Power loss = I²R = (P/V)²R = P²R/V². If V is doubled, loss becomes P²R/(2V)² = P²R/(4V²) = original loss/4. So doubling the voltage reduces the power loss to one-fourth. This is the key reason for high-voltage power transmission.", "correct_answer": "B", "concept_tags": ["power-transmission", "voltage", "efficiency"], "payload": {"question_id": "cuet-phy-ac-adv-20", "subtopic": "power transmission", "topic_name": "AC Circuits — Advanced", "bloom_level": "apply", "options": [{"key": "A", "value": "Half of the original", "is_correct": false}, {"key": "B", "value": "One-fourth of the original", "is_correct": true}, {"key": "C", "value": "Double the original", "is_correct": false}, {"key": "D", "value": "Same as the original", "is_correct": false}], "elimination_hints": ["Loss ∝ 1/V², so doubling V reduces loss by a factor of 4.", "Half would be correct if loss ∝ 1/V, but it''s ∝ 1/V².", "Higher voltage means lower current for same power → much less I²R loss."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The efficiency of a transformer is defined as:", "explanation": "Efficiency η = (output power / input power) × 100%. For an ideal transformer η = 100%. Real transformers have η between 90–99% due to copper losses, eddy current losses, hysteresis losses, and flux leakage.", "correct_answer": "A", "concept_tags": ["transformer", "efficiency", "power"], "payload": {"question_id": "cuet-phy-ac-adv-21", "subtopic": "transformer efficiency", "topic_name": "AC Circuits — Advanced", "bloom_level": "remember", "options": [{"key": "A", "value": "(Output power / Input power) × 100%", "is_correct": true}, {"key": "B", "value": "(Input power / Output power) × 100%", "is_correct": false}, {"key": "C", "value": "(V_s / V_p) × 100%", "is_correct": false}, {"key": "D", "value": "(N_p / N_s) × 100%", "is_correct": false}], "elimination_hints": ["Input/Output ratio would give a value > 100% for a real transformer.", "V_s/V_p is the voltage ratio (turns ratio), not efficiency.", "Efficiency relates power output to power input, not voltages or turns."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "Copper loss (I²R loss) in a transformer is due to:", "explanation": "Copper loss occurs because the primary and secondary windings have finite resistance. When current flows through these windings, energy is dissipated as heat (I²R). It can be reduced by using thick copper wires (low resistance).", "correct_answer": "C", "concept_tags": ["transformer", "copper-loss", "resistance", "heating"], "payload": {"question_id": "cuet-phy-ac-adv-22", "subtopic": "transformer losses", "topic_name": "AC Circuits — Advanced", "bloom_level": "remember", "options": [{"key": "A", "value": "Eddy currents in the core", "is_correct": false}, {"key": "B", "value": "Hysteresis in the core", "is_correct": false}, {"key": "C", "value": "Resistance of the windings", "is_correct": true}, {"key": "D", "value": "Magnetic flux leakage", "is_correct": false}], "elimination_hints": ["Eddy currents cause iron loss, not copper loss.", "Hysteresis loss is due to repeated magnetization of the core.", "Copper loss = I²R, and R is the resistance of the copper windings."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "Eddy current losses in a transformer core are minimized by:", "explanation": "Eddy currents are induced in the transformer core by the changing magnetic flux. Using a laminated core (thin insulated sheets) increases the resistance to eddy current paths, confining them to small loops within each lamination, thereby reducing I²R heating.", "correct_answer": "B", "concept_tags": ["transformer", "eddy-current-loss", "lamination"], "payload": {"question_id": "cuet-phy-ac-adv-23", "subtopic": "transformer losses", "topic_name": "AC Circuits — Advanced", "bloom_level": "understand", "options": [{"key": "A", "value": "Using thick copper windings", "is_correct": false}, {"key": "B", "value": "Using a laminated iron core", "is_correct": true}, {"key": "C", "value": "Increasing the frequency", "is_correct": false}, {"key": "D", "value": "Using a solid iron core", "is_correct": false}], "elimination_hints": ["Thick copper windings reduce copper loss, not eddy current loss.", "Increasing frequency actually increases eddy current losses.", "A solid core allows large eddy current loops — lamination breaks them up."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "Hysteresis loss in a transformer can be minimized by using a core material with:", "explanation": "Hysteresis loss is proportional to the area of the B-H (hysteresis) loop. Soft magnetic materials like soft iron or silicon steel have narrow hysteresis loops (low coercivity and low retentivity), resulting in less energy lost per magnetization cycle.", "correct_answer": "A", "concept_tags": ["transformer", "hysteresis-loss", "soft-iron", "B-H-curve"], "payload": {"question_id": "cuet-phy-ac-adv-24", "subtopic": "transformer losses", "topic_name": "AC Circuits — Advanced", "bloom_level": "understand", "options": [{"key": "A", "value": "Narrow hysteresis loop (e.g. soft iron)", "is_correct": true}, {"key": "B", "value": "Wide hysteresis loop (e.g. steel)", "is_correct": false}, {"key": "C", "value": "High coercivity", "is_correct": false}, {"key": "D", "value": "High retentivity", "is_correct": false}], "elimination_hints": ["Wide hysteresis loop means more area → more energy loss per cycle.", "High coercivity materials (like steel) are used for permanent magnets, not transformer cores.", "Narrow loop = low coercivity + low retentivity = less hysteresis loss."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A transformer with 90% efficiency has a primary voltage of 200 V and delivers power to a 20 Ω load connected to its secondary at 40 V. The primary current drawn is approximately:", "explanation": "Secondary current I_s = V_s/R_load = 40/20 = 2 A. Output power = V_s × I_s = 40 × 2 = 80 W. Efficiency η = P_out/P_in → P_in = P_out/η = 80/0.9 ≈ 88.9 W. Primary current I_p = P_in/V_p = 88.9/200 ≈ 0.44 A.", "correct_answer": "C", "concept_tags": ["transformer", "efficiency", "numerical", "power"], "payload": {"question_id": "cuet-phy-ac-adv-25", "subtopic": "transformer efficiency", "topic_name": "AC Circuits — Advanced", "bloom_level": "apply", "options": [{"key": "A", "value": "0.2 A", "is_correct": false}, {"key": "B", "value": "0.4 A", "is_correct": false}, {"key": "C", "value": "0.44 A", "is_correct": true}, {"key": "D", "value": "0.8 A", "is_correct": false}], "elimination_hints": ["0.4 A assumes 100% efficiency (ideal transformer).", "0.8 A comes from incorrect calculation: I_p must be greater than 0.4 A (ideal) due to losses, but not double.", "P_in = 80/0.9 ≈ 88.9 W → I_p = 88.9/200 ≈ 0.44 A."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "An ideal step-down transformer converts 2200 V to 220 V. If the secondary coil has 50 turns, the number of turns in the primary coil is:", "explanation": "For an ideal transformer, V_p/V_s = N_p/N_s. So N_p = N_s × (V_p/V_s) = 50 × (2200/220) = 50 × 10 = 500 turns. The step-down ratio is 10:1.", "correct_answer": "B", "concept_tags": ["transformer", "turns-ratio", "step-down", "numerical"], "payload": {"question_id": "cuet-phy-ac-adv-26", "subtopic": "transformer calculations", "topic_name": "AC Circuits — Advanced", "bloom_level": "apply", "options": [{"key": "A", "value": "50", "is_correct": false}, {"key": "B", "value": "500", "is_correct": true}, {"key": "C", "value": "5000", "is_correct": false}, {"key": "D", "value": "5", "is_correct": false}], "elimination_hints": ["50 turns for primary would mean a 1:1 ratio, not a step-down.", "V_p/V_s = 2200/220 = 10, so N_p = 10 × N_s = 10 × 50 = 500.", "5000 would require a 100:1 ratio which doesn''t match 2200:220."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "In a transformer, flux leakage leads to:", "explanation": "Flux leakage means not all the magnetic flux produced by the primary coil links with the secondary coil. This reduces the EMF induced in the secondary, decreasing the output voltage and power. It reduces the efficiency of the transformer.", "correct_answer": "D", "concept_tags": ["transformer", "flux-leakage", "efficiency"], "payload": {"question_id": "cuet-phy-ac-adv-27", "subtopic": "transformer losses", "topic_name": "AC Circuits — Advanced", "bloom_level": "understand", "options": [{"key": "A", "value": "Increased output voltage", "is_correct": false}, {"key": "B", "value": "Increased efficiency", "is_correct": false}, {"key": "C", "value": "No effect on performance", "is_correct": false}, {"key": "D", "value": "Reduced output voltage and efficiency", "is_correct": true}], "elimination_hints": ["Less flux linking secondary means less induced EMF → lower output voltage.", "Flux leakage is a loss mechanism — it reduces efficiency, not increases it.", "Any energy lost to leakage flux is energy not transferred to the secondary."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A town 10 km away receives electrical power from a power plant. The power plant generates 2 MW at 10 kV. The two-wire transmission line has a resistance of 0.5 Ω/km. The power loss in the line is:", "explanation": "Total wire length = 2 × 10 = 20 km (two wires). Total resistance R = 20 × 0.5 = 10 Ω. Current I = P/V = 2 × 10⁶ / (10 × 10³) = 200 A. Power loss = I²R = 200² × 10 = 40000 × 10 = 400,000 W = 400 kW. Percentage loss = (400/2000) × 100 = 20%.", "correct_answer": "C", "concept_tags": ["power-transmission", "line-loss", "numerical"], "payload": {"question_id": "cuet-phy-ac-adv-28", "subtopic": "power transmission", "topic_name": "AC Circuits — Advanced", "bloom_level": "apply", "options": [{"key": "A", "value": "100 kW", "is_correct": false}, {"key": "B", "value": "200 kW", "is_correct": false}, {"key": "C", "value": "400 kW", "is_correct": true}, {"key": "D", "value": "800 kW", "is_correct": false}], "elimination_hints": ["Two wires of 10 km each → total resistance = 20 × 0.5 = 10 Ω.", "I = 2 × 10⁶ / 10⁴ = 200 A; Loss = 200² × 10 = 400,000 W.", "200 kW uses only one wire''s resistance (5 Ω) — must count both wires."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "In an LC oscillating circuit, the capacitor has maximum charge q₀ and the inductance is L. The maximum current in the circuit is:", "explanation": "By energy conservation: ½q₀²/C = ½LI₀². Also, I₀ = q₀ω = q₀/√(LC). Alternatively, from ½q₀²/C = ½LI₀², we get I₀ = q₀/√(LC). The maximum current occurs when the capacitor is fully discharged.", "correct_answer": "A", "concept_tags": ["LC-oscillation", "maximum-current", "energy-conservation"], "payload": {"question_id": "cuet-phy-ac-adv-29", "subtopic": "LC oscillations", "topic_name": "AC Circuits — Advanced", "bloom_level": "apply", "options": [{"key": "A", "value": "q₀/√(LC)", "is_correct": true}, {"key": "B", "value": "q₀√(LC)", "is_correct": false}, {"key": "C", "value": "q₀/(LC)", "is_correct": false}, {"key": "D", "value": "q₀√(L/C)", "is_correct": false}], "elimination_hints": ["q₀√(LC) has dimensions of charge × time, not current.", "I₀ = q₀ω = q₀ × 1/√(LC) = q₀/√(LC).", "Dimensional check: [q₀/√(LC)] = C/√(H·F) = C/√(s²) = C/s = A ✓"]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "An LC circuit has L = 0.2 H and C = 5 μF. The capacitor is initially charged to 10 mC. The maximum current in the circuit is:", "explanation": "I₀ = q₀/√(LC) = 10 × 10⁻³ / √(0.2 × 5 × 10⁻⁶) = 10⁻² / √(10⁻⁶) = 10⁻² / 10⁻³ = 10 A. Alternatively, ω = 1/√(LC) = 1/10⁻³ = 1000 rad/s, and I₀ = q₀ω = 10⁻² × 10³ = 10 A.", "correct_answer": "D", "concept_tags": ["LC-oscillation", "maximum-current", "numerical"], "payload": {"question_id": "cuet-phy-ac-adv-30", "subtopic": "LC oscillations", "topic_name": "AC Circuits — Advanced", "bloom_level": "apply", "options": [{"key": "A", "value": "0.1 A", "is_correct": false}, {"key": "B", "value": "1 A", "is_correct": false}, {"key": "C", "value": "5 A", "is_correct": false}, {"key": "D", "value": "10 A", "is_correct": true}], "elimination_hints": ["LC = 0.2 × 5 × 10⁻⁶ = 10⁻⁶, so √(LC) = 10⁻³.", "I₀ = q₀/√(LC) = 10 × 10⁻³ / 10⁻³ = 10 A.", "Common error: forgetting to convert mC to C gives I₀ = 10000 A (way too high)."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "In the LC-SHM analogy, the quantity analogous to the potential energy (½kx²) of the spring-mass system is:", "explanation": "In the analogy: q ↔ x, I ↔ v, L ↔ m, 1/C ↔ k. Potential energy ½kx² ↔ ½(1/C)q² = q²/(2C), which is the energy stored in the capacitor (electric field energy). Kinetic energy ½mv² ↔ ½LI² (magnetic energy in the inductor).", "correct_answer": "B", "concept_tags": ["LC-oscillation", "SHM-analogy", "energy"], "payload": {"question_id": "cuet-phy-ac-adv-31", "subtopic": "LC oscillations — SHM analogy", "topic_name": "AC Circuits — Advanced", "bloom_level": "understand", "options": [{"key": "A", "value": "½LI² (energy in inductor)", "is_correct": false}, {"key": "B", "value": "q²/(2C) (energy in capacitor)", "is_correct": true}, {"key": "C", "value": "½CV² (energy in capacitor)", "is_correct": false}, {"key": "D", "value": "LI (flux linkage)", "is_correct": false}], "elimination_hints": ["½LI² is analogous to ½mv² (kinetic energy), not potential energy.", "½CV² is the same as q²/(2C) but written in terms of V; the direct analogy uses q (↔ x).", "Potential energy involves the ''displacement'' variable: ½kx² ↔ q²/(2C)."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "Which of the following is NOT a source of energy loss in a real transformer?", "explanation": "Energy losses in a real transformer include: copper loss (I²R in windings), eddy current loss (induced currents in core), hysteresis loss (repeated magnetization of core), and flux leakage. Dielectric loss occurs in capacitors, not in transformers.", "correct_answer": "D", "concept_tags": ["transformer", "energy-loss", "efficiency"], "payload": {"question_id": "cuet-phy-ac-adv-32", "subtopic": "transformer losses", "topic_name": "AC Circuits — Advanced", "bloom_level": "remember", "options": [{"key": "A", "value": "Copper loss", "is_correct": false}, {"key": "B", "value": "Eddy current loss", "is_correct": false}, {"key": "C", "value": "Hysteresis loss", "is_correct": false}, {"key": "D", "value": "Dielectric loss", "is_correct": true}], "elimination_hints": ["Copper loss (I²R) definitely occurs in the windings.", "Eddy current and hysteresis losses occur in the iron core.", "Dielectric loss is associated with capacitors and insulators, not transformer operation."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A step-up transformer has a turns ratio of 1:10. If the primary current is 5 A, the secondary current for an ideal transformer is:", "explanation": "For an ideal transformer, I_p/I_s = N_s/N_p (current is inversely proportional to turns ratio). I_s = I_p × (N_p/N_s) = 5 × (1/10) = 0.5 A. A step-up transformer increases voltage but decreases current proportionally.", "correct_answer": "A", "concept_tags": ["transformer", "current-ratio", "step-up", "numerical"], "payload": {"question_id": "cuet-phy-ac-adv-33", "subtopic": "transformer calculations", "topic_name": "AC Circuits — Advanced", "bloom_level": "apply", "options": [{"key": "A", "value": "0.5 A", "is_correct": true}, {"key": "B", "value": "5 A", "is_correct": false}, {"key": "C", "value": "50 A", "is_correct": false}, {"key": "D", "value": "0.05 A", "is_correct": false}], "elimination_hints": ["5 A would mean no change in current (1:1 transformer).", "50 A would mean the current increased — this happens in a step-down, not step-up.", "In a step-up transformer, voltage increases so current must decrease: I_s = 5/10 = 0.5 A."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "Assertion (A): A transformer cannot work with direct current (DC).\nReason (R): A transformer works on the principle of mutual induction which requires a changing magnetic flux.", "explanation": "DC produces a constant current and hence a constant magnetic flux in the primary. A constant flux does not induce any EMF in the secondary (Faraday''s law: EMF = −dΦ/dt = 0 for constant Φ). Moreover, with DC, the primary acts as a short circuit (only resistance, no reactance), drawing excessive current that can burn the windings.", "correct_answer": "A", "concept_tags": ["transformer", "DC", "mutual-induction", "assertion-reason"], "payload": {"question_id": "cuet-phy-ac-adv-34", "subtopic": "transformer principle", "topic_name": "AC Circuits — Advanced", "bloom_level": "evaluate", "options": [{"key": "A", "value": "Both A and R are true, and R is the correct explanation of A", "is_correct": true}, {"key": "B", "value": "Both A and R are true, but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "value": "A is true but R is false", "is_correct": false}, {"key": "D", "value": "A is false but R is true", "is_correct": false}], "elimination_hints": ["The transformer indeed cannot work with DC — assertion A is true.", "Mutual induction requires dΦ/dt ≠ 0, which needs AC — reason R is true.", "R directly explains A: the changing flux requirement is why DC fails."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "In an LCR circuit connected to an AC source, the current is in phase with the voltage. This means:", "explanation": "Current in phase with voltage means φ = 0°, which occurs when X_L = X_C (reactances cancel). This is the condition for resonance in a series LCR circuit. At resonance, Z = R (minimum impedance) and current is maximum.", "correct_answer": "C", "concept_tags": ["resonance", "phase", "LCR-circuit"], "payload": {"question_id": "cuet-phy-ac-adv-35", "subtopic": "resonance conditions", "topic_name": "AC Circuits — Advanced", "bloom_level": "understand", "options": [{"key": "A", "value": "X_L > X_C", "is_correct": false}, {"key": "B", "value": "X_L < X_C", "is_correct": false}, {"key": "C", "value": "X_L = X_C (resonance)", "is_correct": true}, {"key": "D", "value": "R = 0", "is_correct": false}], "elimination_hints": ["X_L > X_C makes the circuit inductive — current lags voltage.", "X_L < X_C makes the circuit capacitive — current leads voltage.", "In-phase condition requires net reactance = 0, i.e., X_L = X_C."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "In an LCR series circuit, R = 10 Ω, L = 0.5 H, and C = 50 μF. The circuit is connected to a 220 V, 50 Hz AC source. The current in the circuit is approximately:", "explanation": "ω = 2πf = 2π × 50 = 100π rad/s. X_L = ωL = 100π × 0.5 = 50π ≈ 157 Ω. X_C = 1/(ωC) = 1/(100π × 50 × 10⁻⁶) = 1/(5π × 10⁻³) = 200/π ≈ 63.7 Ω. Z = √(R² + (X_L − X_C)²) = √(100 + (157 − 63.7)²) = √(100 + 8700) = √8800 ≈ 93.8 Ω. I = V/Z = 220/93.8 ≈ 2.34 A.", "correct_answer": "B", "concept_tags": ["LCR-circuit", "impedance", "numerical", "current"], "payload": {"question_id": "cuet-phy-ac-adv-36", "subtopic": "LCR circuit numerical", "topic_name": "AC Circuits — Advanced", "bloom_level": "apply", "options": [{"key": "A", "value": "1.0 A", "is_correct": false}, {"key": "B", "value": "2.3 A", "is_correct": true}, {"key": "C", "value": "5.0 A", "is_correct": false}, {"key": "D", "value": "22.0 A", "is_correct": false}], "elimination_hints": ["22.0 A would require Z = 10 Ω (only R), ignoring reactances.", "X_L − X_C ≈ 93 Ω, so Z ≈ √(100 + 8700) ≈ 94 Ω.", "I = 220/94 ≈ 2.3 A."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "In the above circuit (R = 10 Ω, L = 0.5 H, C = 50 μF, f = 50 Hz), the resonant frequency is approximately:", "explanation": "f₀ = 1/(2π√(LC)) = 1/(2π√(0.5 × 50 × 10⁻⁶)) = 1/(2π√(25 × 10⁻⁶)) = 1/(2π × 5 × 10⁻³) = 1/(10π × 10⁻³) = 1000/(10π) = 100/π ≈ 31.8 Hz. The circuit is being driven at 50 Hz, which is above resonance.", "correct_answer": "A", "concept_tags": ["resonant-frequency", "LCR-circuit", "numerical"], "payload": {"question_id": "cuet-phy-ac-adv-37", "subtopic": "LCR circuit numerical", "topic_name": "AC Circuits — Advanced", "bloom_level": "apply", "options": [{"key": "A", "value": "100/π Hz ≈ 31.8 Hz", "is_correct": true}, {"key": "B", "value": "50 Hz", "is_correct": false}, {"key": "C", "value": "100 Hz", "is_correct": false}, {"key": "D", "value": "200/π Hz ≈ 63.7 Hz", "is_correct": false}], "elimination_hints": ["50 Hz is the driving frequency, not the resonant frequency.", "LC = 0.5 × 50 × 10⁻⁶ = 25 × 10⁻⁶, √(LC) = 5 × 10⁻³.", "f₀ = 1/(2π × 5 × 10⁻³) = 100/π ≈ 31.8 Hz."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The power factor of a series RL circuit with R = 30 Ω and X_L = 40 Ω is:", "explanation": "Power factor cos φ = R/Z. Impedance Z = √(R² + X_L²) = √(900 + 1600) = √2500 = 50 Ω. cos φ = R/Z = 30/50 = 0.6. The phase angle φ = cos⁻¹(0.6) ≈ 53.13°.", "correct_answer": "C", "concept_tags": ["power-factor", "RL-circuit", "impedance", "numerical"], "payload": {"question_id": "cuet-phy-ac-adv-38", "subtopic": "power factor", "topic_name": "AC Circuits — Advanced", "bloom_level": "apply", "options": [{"key": "A", "value": "0.4", "is_correct": false}, {"key": "B", "value": "0.5", "is_correct": false}, {"key": "C", "value": "0.6", "is_correct": true}, {"key": "D", "value": "0.8", "is_correct": false}], "elimination_hints": ["0.8 = 40/50 = X_L/Z, which is sin φ, not cos φ.", "0.4 = R/X_L — this is not the power factor formula.", "Power factor = R/Z = 30/50 = 0.6. It''s a 3-4-5 right triangle scaled by 10."]}}]'::jsonb, 'deploy-2026-03-05-b06');

